    if raw.lower().startswith("github dependabot organization private names "):
        dependabot_org_secrets_text_sanitizer = globals().get("_safe_github_dependabot_org_secrets_origin_text")
        if callable(dependabot_org_secrets_text_sanitizer):
            dependabot_org_secrets_text = dependabot_org_secrets_text_sanitizer(raw)
