    if raw.lower().startswith("github actions organization private name "):
        org_single_secret_text_sanitizer = globals().get("_safe_github_actions_org_single_secret_origin_text")
        if callable(org_single_secret_text_sanitizer):
            org_single_secret_text = org_single_secret_text_sanitizer(raw)
            if isinstance(org_single_secret_text, str) and org_single_secret_text:
                return org_single_secret_text
        return f"capy-memory://{source_id}"
    if raw.lower().startswith("github actions organization secrets "):
        org_secrets_text_sanitizer = globals().get("_safe_github_actions_org_secrets_origin_text")
        if callable(org_secrets_text_sanitizer):
            org_secrets_text = org_secrets_text_sanitizer(raw)
            if isinstance(org_secrets_text, str) and org_secrets_text:
                return org_secrets_text
        return f"capy-memory://{source_id}"
    if raw.lower().startswith("github secret scanning alerts "):
        secret_scanning_alerts_text_sanitizer = globals().get("_safe_github_secret_scanning_alerts_origin_text")
        if callable(secret_scanning_alerts_text_sanitizer):
            secret_scanning_alerts_text = secret_scanning_alerts_text_sanitizer(raw)
            if isinstance(secret_scanning_alerts_text, str) and secret_scanning_alerts_text:
                return secret_scanning_alerts_text
        return f"capy-memory://{source_id}"
    single_artifact_route_hint = globals().get("_github_single_artifact_route_path_hint_matches")
    single_artifact_safe_origin = globals().get("_github_single_artifact_safe_origin")
    if (
        callable(single_artifact_route_hint)
        and single_artifact_route_hint(raw)
        and (not callable(single_artifact_safe_origin) or not single_artifact_safe_origin(raw))
    ):
        return f"capy-memory://{source_id}"
    if raw.startswith(("/", "~", "\\\\")) or re.match(r"^[A-Za-z]:[\\/]", raw):
        return f"capy-memory://{source_id}"
    try:
        parts = urlsplit(raw)
    except ValueError:
        return f"capy-memory://{source_id}"
    if parts.scheme == "file":
        return f"capy-memory://{source_id}"
    if parts.scheme in {"http", "https"} and parts.netloc and "api.github.com" in parts.netloc.lower():
        forks_matcher = globals().get("_github_forks_path_matches")
        forks_raw_origin_is_refreshable = globals().get("_github_forks_raw_origin_is_refreshable")
