def _github_single_artifact_route_path_hint_matches(origin_uri: str) -> bool:
    raw_route_text = str(origin_uri or "").split("?", 1)[0].split("#", 1)[0].strip()
    candidates: list[str] = []
    if raw_route_text.lower().startswith("api.github.com"):
        candidates.append(raw_route_text)
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        parts = None

    if parts is not None:
        if parts.scheme or parts.netloc:
            authority = (parts.netloc or "").strip().lower()
            if (parts.hostname or "").strip().lower() == "api.github.com":
                candidates.append("api.github.com" + (parts.path or ""))
            elif (
                authority == "api.github.com"
                or authority.startswith("api.github.com:")
                or authority.startswith("api.github.com.")
            ):
                candidates.append((parts.netloc or "") + (parts.path or ""))
        else:
            candidates.append(raw_route_text)

    for candidate in candidates:
        for route_text in (candidate, unquote(candidate)):
            path = route_text.split("/")
            lowered = [segment.lower() for segment in path]
            host_hint = lowered[0] if lowered else ""
            host_hint_matches = (
                host_hint == "api.github.com"
                or host_hint.startswith("api.github.com:")
                or host_hint.startswith("api.github.com.")
            )
            if (
                len(path) >= 7
                and host_hint_matches
                and lowered[1] == "repos"
                and lowered[4] == "actions"
                and lowered[5] == "artifacts"
            ):
                return True
    return False


