def _github_single_artifact_fetch_origin_from_origin_text(origin_text: str) -> str:
    text = _safe_public_text(origin_text, limit=240)
    prefix = "github actions artifact "
    if not text.startswith(prefix):
        return ""
    rest = text.removeprefix(prefix).strip()
    match = re.fullmatch(r"([A-Za-z0-9][A-Za-z0-9._-]{0,119}/[A-Za-z0-9][A-Za-z0-9._-]{0,119}) ([1-9][0-9]*)", rest)
    if not match:
        return ""
    repo, artifact_id = match.groups()
    owner, name = repo.split("/", 1)
    if not _github_repo_path_segment_is_safe(owner) or not _github_repo_path_segment_is_safe(name):
        return ""
    return f"https://api.github.com/repos/{owner}/{name}/actions/artifacts/{artifact_id}"


