    _repo, artifact_id = path_info
    if not isinstance(payload, dict):
        return False
    if _json_payload_is_feed(payload) or any(key in payload for key in ("version", "items")):
        return False
    payload_artifact_id = _safe_optional_nonnegative_int(payload.get("id"))
    if payload_artifact_id != artifact_id:
        return False
    return _github_workflow_artifact_is_safe(payload)


