    path_info = _github_single_artifact_path_info(origin_uri)
    repo, artifact_id = path_info if path_info is not None else ("repository", 0)
    name = _safe_public_text(payload.get("name"), limit=200)
    size = _safe_optional_nonnegative_int(payload.get("size_in_bytes"))
    artifact_parts = [f"GitHub actions artifact {repo} #{artifact_id}", f"artifact: {name}", f"id: {artifact_id}"]
    if size is not None:
        artifact_parts.append(f"size bytes: {size}")
    if isinstance(payload.get("expired"), bool):
        artifact_parts.append(f"expired: {str(payload['expired']).lower()}")
    for field, label in (("created_at", "created"), ("updated_at", "updated"), ("expires_at", "expires")):
        timestamp = _safe_public_text(payload.get(field), limit=80)
        if timestamp:
            artifact_parts.append(f"{label}: {timestamp}")
    return _bounded_refresh_summary("; ".join(artifact_parts))


