_GITHUB_CHECK_RUN_ANNOTATION_SEVERITIES = {
    "none",
    "note",
    "notice",
    "low",
    "medium",
    "moderate",
    "warning",
    "high",
    "critical",
    "error",
    "failure",
}


def _github_check_run_annotations_route_path_matches(origin_uri: str) -> bool:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return False
    raw_netloc = (parts.netloc or "").strip().lower()
    if "api.github.com" not in raw_netloc:
        return False
    raw_path = parts.path or ""
    decoded_path = unquote(raw_path)
    raw_path_lower = raw_path.lower()
    decoded_path_lower = decoded_path.lower()
    return (
        "/repos/" in raw_path_lower
        and "/check-runs/" in raw_path_lower
        and "annotations" in raw_path_lower
    ) or (
        "/repos/" in decoded_path_lower
        and "/check-runs/" in decoded_path_lower
        and "annotations" in decoded_path_lower
    )


def _github_check_run_annotations_path_info(origin_uri: str) -> tuple[str, int] | None:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return None
    if parts.scheme != "https" or (parts.netloc or "").strip() != "api.github.com":
        return None
    if unquote(parts.path or "") != (parts.path or ""):
        return None
    path = parts.path.split("/")
    if (
        len(path) != 7
        or path[0] != ""
        or path[1] != "repos"
        or not _github_repo_path_segment_is_safe(path[2])
        or not _github_repo_path_segment_is_safe(path[3])
        or path[4] != "check-runs"
        or not re.fullmatch(r"[1-9][0-9]{0,19}", path[5])
        or path[6] != "annotations"
    ):
        return None
    try:
        check_run_id = int(path[5])
    except ValueError:
        return None
    return f"{path[2]}/{path[3]}", check_run_id


def _github_check_run_annotations_safe_origin(origin_uri: str) -> str:
    if not _github_check_run_annotations_route_path_matches(origin_uri):
        return ""
    if not _github_https_authority_is_exact(origin_uri, "api.github.com"):
        return ""
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return ""
    safe_origin = urlunsplit(("https", "api.github.com", parts.path, "", ""))
    if _github_check_run_annotations_path_info(safe_origin) is None:
        return ""
    return safe_origin


def _github_check_run_annotations_public_origin(origin_uri: str) -> str:
    info = _github_check_run_annotations_path_info(origin_uri)
    if info is None:
        return ""
    repo, check_run_id = info
    return f"github check run annotations {repo} check run {check_run_id}"


def _github_check_run_annotations_fetch_origin_from_origin_text(origin_text: Any) -> str:
    text = _safe_public_text(origin_text, limit=240)
    match = re.fullmatch(
        r"github check run annotations ([A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+) check run ([1-9][0-9]{0,19})",
        text,
        flags=re.IGNORECASE,
    )
    if not match:
        return ""
    owner, repo = match.group(1).split("/", 1)
    if not _github_repo_path_segment_is_safe(owner) or not _github_repo_path_segment_is_safe(repo):
        return ""
    try:
        check_run_id = int(match.group(2))
    except ValueError:
        return ""
    return f"https://api.github.com/repos/{owner}/{repo}/check-runs/{check_run_id}/annotations"


_GITHUB_CHECK_RUN_ANNOTATIONS_MAX_ROWS = 100


def _github_check_run_annotation_row_is_safe(row: Any) -> bool:
    if not isinstance(row, dict):
        return False
    level = _safe_public_text(row.get("annotation_level"), limit=60).lower()
    if not level or level not in _GITHUB_CHECK_RUN_ANNOTATION_LEVELS or _refresh_value_is_blocked(level):
        return False
    if row.get("severity") is not None:
        severity = _safe_public_text(row.get("severity"), limit=60).lower()
        if (
            not severity
            or severity not in _GITHUB_CHECK_RUN_ANNOTATION_SEVERITIES
            or _refresh_value_is_blocked(severity)
        ):
            return False
    return True


