def _github_single_deployment_path_info(origin_uri: str) -> tuple[str, int] | None:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return None
    if (parts.hostname or "").strip().lower() != "api.github.com":
        return None
    path = parts.path.split("/")
    if (
        len(path) != 6
        or path[0] != ""
        or path[1] != "repos"
        or path[4] != "deployments"
        or not _github_repo_path_segment_is_safe(path[2])
        or not _github_repo_path_segment_is_safe(path[3])
        or not re.fullmatch(r"[1-9][0-9]*", path[5])
    ):
        return None
    return f"{path[2]}/{path[3]}", int(path[5])


def _github_single_deployment_path_matches(origin_uri: str) -> bool:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return False
    if (parts.hostname or "").strip().lower() != "api.github.com":
        return False
    path = parts.path.split("/")
    return (
        len(path) == 6
        and path[0] == ""
        and path[1] == "repos"
        and path[4] == "deployments"
    )


def _github_single_deployment_route_path_matches(origin_uri: str) -> bool:
    if _github_single_deployment_path_matches(origin_uri):
        return True
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return False
    if (parts.hostname or "").strip().lower() != "api.github.com":
        return False
    raw_path = parts.path
    if "%" not in raw_path:
        return False

    def decoded_path_matches(candidate: str) -> bool:
        decoded_path = candidate.split("/")
        return (
            len(decoded_path) >= 6
            and decoded_path[0] == ""
            and decoded_path[1] == "repos"
            and _github_repo_path_segment_is_safe(decoded_path[2])
            and _github_repo_path_segment_is_safe(decoded_path[3])
            and decoded_path[4] == "deployments"
            and re.fullmatch(r"[1-9][0-9]*", decoded_path[5]) is not None
        )

    decoded = raw_path
    for _attempt in range(3):
        next_decoded = unquote(decoded)
        if next_decoded == decoded:
            break
        decoded = next_decoded
        if decoded_path_matches(decoded):
            return True
    return False


def _github_deployments_final_url_matches_origin(origin_uri: str, final_url: Any) -> bool:
    if not isinstance(final_url, str):
        return False
    origin_repo = _github_deployments_path_repo(origin_uri)
    if not origin_repo:
        return False
    try:
        origin_parts = urlsplit(origin_uri)
    except ValueError:
        return False
    if (
        origin_parts.scheme != "https"
        or not _github_raw_authority_is_exact(origin_uri, "api.github.com")
        or origin_parts.query
        or origin_parts.fragment
    ):
        return False
    origin_path = origin_parts.path.split("/")
    if (
        len(origin_path) != 5
        or origin_path[0] != ""
        or origin_path[1] != "repos"
        or origin_path[4] != "deployments"
        or not _github_repo_path_segment_is_safe(origin_path[2])
        or not _github_repo_path_segment_is_safe(origin_path[3])
    ):
        return False
    expected = urlunsplit(("https", "api.github.com", f"/repos/{origin_path[2]}/{origin_path[3]}/deployments", "", ""))
    return (
        final_url == expected
        and _github_raw_authority_is_exact(final_url, "api.github.com")
        and _github_deployments_path_repo(final_url) == origin_repo
    )


def _github_single_deployment_final_url_matches_origin(origin_uri: str, final_url: Any) -> bool:
    if not isinstance(final_url, str):
        return False
    origin_info = _github_single_deployment_path_info(origin_uri)
    if origin_info is None:
        return False
    try:
        origin_parts = urlsplit(origin_uri)
    except ValueError:
        return False
    if (
        origin_parts.scheme != "https"
        or not _github_raw_authority_is_exact(origin_uri, "api.github.com")
        or origin_parts.query
        or origin_parts.fragment
    ):
        return False
    origin_path = origin_parts.path.split("/")
    if len(origin_path) != 6:
        return False
    expected = urlunsplit(("https", "api.github.com", f"/repos/{origin_path[2]}/{origin_path[3]}/deployments/{origin_path[5]}", "", ""))
    return (
        final_url == expected
        and _github_raw_authority_is_exact(final_url, "api.github.com")
        and _github_single_deployment_path_info(final_url) == origin_info
    )


_GITHUB_DEPLOYMENT_TASKS = {"deploy", "deploy:migrations", "rollback", "rollback:migrations"}
_GITHUB_DEPLOYMENTS_MAX_ROWS = 100
_GITHUB_DEPLOYMENT_TEXT_RE = re.compile(r"[A-Za-z0-9][A-Za-z0-9 ._/#:+-]{0,119}")


def _github_deployment_text_is_safe(value: Any, *, limit: int = 120) -> bool:
    if not isinstance(value, str):
        return False
    text = _safe_public_text(value, limit=limit)
    if not text or text != value.strip():
        return False
    if _refresh_value_is_blocked(value) or _REFRESH_TITLE_BLOCKED_VALUE_RE.search(text):
        return False
    return bool(_GITHUB_DEPLOYMENT_TEXT_RE.fullmatch(text))


def _github_deployment_row_is_safe(row: Any) -> bool:
    if not isinstance(row, dict):
        return False
    deployment_id = _safe_optional_nonnegative_int(row.get("id"))
    if deployment_id is None or deployment_id <= 0:
        return False
    if not _github_deployment_text_is_safe(row.get("ref")):
        return False
    raw_sha = row.get("sha")
    if not isinstance(raw_sha, str) or not re.fullmatch(r"[A-Fa-f0-9]{40}", raw_sha):
        return False
    task = _safe_public_text(row.get("task"), limit=80).lower()
    if not task or task not in _GITHUB_DEPLOYMENT_TASKS:
        return False
    if not _github_deployment_text_is_safe(row.get("environment"), limit=80):
        return False
    for field in ("production_environment", "transient_environment"):
        raw_bool = row.get(field)
        if raw_bool is not None and not isinstance(raw_bool, bool):
            return False
    for field in ("created_at", "updated_at"):
        raw_timestamp = row.get(field)
        if raw_timestamp is not None and not _safe_iso_timestamp(raw_timestamp):
            return False
    for raw_value in (row.get("id"), row.get("ref"), row.get("sha"), row.get("task"), row.get("environment"), row.get("created_at"), row.get("updated_at")):
        if _refresh_value_is_blocked(raw_value):
            return False
    return True


def _json_payload_is_github_deployments_metadata(origin_uri: str, payload: Any) -> bool:
    if not _github_deployments_path_repo(origin_uri):
        return False
    if not isinstance(payload, list) or len(payload) > _GITHUB_DEPLOYMENTS_MAX_ROWS:
        return False
    return all(_github_deployment_row_is_safe(row) for row in payload)


def _json_payload_is_github_single_deployment_metadata(origin_uri: str, payload: Any) -> bool:
    path_info = _github_single_deployment_path_info(origin_uri)
    if path_info is None:
        return False
    if not isinstance(payload, dict):
        return False
    if _json_payload_is_feed(payload):
        return False
    _repo, deployment_id = path_info
    return _github_deployment_row_is_safe(payload) and payload.get("id") == deployment_id


def _github_deployments_refresh_summary(origin_uri: str, payload: list[Any]) -> str:
    repo = _github_deployments_path_repo(origin_uri) or "repository"
    safe_rows = [row for row in payload if _github_deployment_row_is_safe(row)]
    parts = [f"GitHub deployments for {repo}", f"deployment count: {len(payload)}"]
    for row in safe_rows[:5]:
        deployment_id = _safe_optional_nonnegative_int(row.get("id")) or 0
        ref = _safe_public_text(row.get("ref"), limit=120)
        sha = _safe_public_text(row.get("sha"), limit=40)[:12]
        task = _safe_public_text(row.get("task"), limit=80).lower()
        environment = _safe_public_text(row.get("environment"), limit=80)
