_GITHUB_DEPLOYMENT_STATUS_STATES = {"error", "failure", "inactive", "in_progress", "queued", "pending", "success"}
_GITHUB_DEPLOYMENT_STATUSES_MAX_ROWS = 100


def _github_deployment_statuses_path_info(origin_uri: str) -> tuple[str, int] | None:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return None
    if (parts.hostname or "").strip().lower() != "api.github.com":
        return None
    path = parts.path.split("/")
    if (
        len(path) != 7
        or path[0] != ""
        or path[1] != "repos"
        or path[4] != "deployments"
        or path[6] != "statuses"
        or not _github_repo_path_segment_is_safe(path[2])
        or not _github_repo_path_segment_is_safe(path[3])
        or not re.fullmatch(r"[1-9][0-9]*", path[5])
    ):
        return None
    return f"{path[2]}/{path[3]}", int(path[5])


def _github_deployment_statuses_final_url_matches_origin(origin_uri: str, final_url: Any) -> bool:
    if not isinstance(final_url, str):
        return False
    origin_info = _github_deployment_statuses_path_info(origin_uri)
    if origin_info is None:
        return False
    try:
        origin_parts = urlsplit(origin_uri)
    except ValueError:
        return False
    if (
        origin_parts.scheme != "https"
        or not _github_raw_authority_is_exact(origin_uri, "api.github.com")
        or origin_parts.query
        or origin_parts.fragment
    ):
        return False
    origin_path = origin_parts.path.split("/")
    if len(origin_path) != 7:
        return False
    expected = urlunsplit(
        (
            "https",
            "api.github.com",
            f"/repos/{origin_path[2]}/{origin_path[3]}/deployments/{origin_path[5]}/statuses",
            "",
            "",
        )
    )
    return (
        final_url == expected
        and _github_raw_authority_is_exact(final_url, "api.github.com")
        and _github_deployment_statuses_path_info(final_url) == origin_info
    )


