def _github_environment_secrets_public_key_route_path_matches(origin_uri: str) -> bool:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return False

    def _segments_match(path_segments: list[str]) -> bool:
        lowered = [segment.lower() for segment in path_segments]
        return (
            len(path_segments) >= 8
            and path_segments[0] == ""
            and lowered[1] == "repos"
            and lowered[4] == "environments"
            and lowered[6] == "secrets"
            and lowered[7].startswith("public-key")
        )

    raw_path = parts.path.split("/")
    if _segments_match(raw_path):
        return True
    decoded_path = unquote(parts.path).split("/")
    if _segments_match(decoded_path):
        return True
    return False


