_GITHUB_ENVIRONMENT_DEPLOYMENT_BRANCH_POLICY_TYPES = {"branch", "tag"}
_GITHUB_ENVIRONMENT_DEPLOYMENT_BRANCH_POLICIES_MAX_ROWS = 100


def _github_environment_deployment_branch_policy_name_is_safe(value: Any) -> bool:
    if not isinstance(value, str):
        return False
    name = _safe_public_text(value, limit=120)
    if not name or name != value.strip():
        return False
    if _refresh_value_is_blocked(name) or _REFRESH_TITLE_BLOCKED_VALUE_RE.search(name):
        return False
    if re.search(r"https?://|www\.|javascript\s*:|\btoken=", name, flags=re.IGNORECASE):
        return False
    return bool(re.fullmatch(r"[A-Za-z0-9*][A-Za-z0-9 ._/*:+@(),=-]{0,119}", name))


def _github_environment_deployment_branch_policy_row_is_safe(row: Any) -> bool:
    if not isinstance(row, dict):
        return False
    policy_id = _safe_optional_nonnegative_int(row.get("id"))
    if policy_id is None:
        return False
    if not _github_environment_deployment_branch_policy_name_is_safe(row.get("name")):
        return False
    policy_type = _safe_public_text(row.get("type"), limit=40).lower()
    if policy_type not in _GITHUB_ENVIRONMENT_DEPLOYMENT_BRANCH_POLICY_TYPES:
        return False
    for raw_value in (row.get("id"), row.get("name"), row.get("type")):
        if _refresh_value_is_blocked(raw_value):
            return False
    return True


def _json_payload_is_github_environment_deployment_branch_policy_metadata(origin_uri: str, payload: Any) -> bool:
    path_info = _github_environment_deployment_branch_policy_path_info(origin_uri)
    if path_info is None:
        return False
    if not isinstance(payload, dict):
        return False
    if _json_payload_is_feed(payload) or "items" in payload or "version" in payload:
        return False
    if not _github_environment_deployment_branch_policy_row_is_safe(payload):
        return False
    _repo, _environment, policy_id = path_info
    payload_policy_id = _safe_optional_nonnegative_int(payload.get("id"))
    return payload_policy_id == policy_id


def _json_payload_is_github_environment_deployment_branch_policies_metadata(origin_uri: str, payload: Any) -> bool:
    if _github_environment_deployment_branch_policies_path_info(origin_uri) is None:
        return False
    if not isinstance(payload, dict):
        return False
    if _json_payload_is_feed(payload) or "items" in payload or "version" in payload:
        return False
    total_count = _safe_optional_nonnegative_int(payload.get("total_count"))
    branch_policies = payload.get("branch_policies")
    if total_count is None or not isinstance(branch_policies, list):
        return False
    if len(branch_policies) > _GITHUB_ENVIRONMENT_DEPLOYMENT_BRANCH_POLICIES_MAX_ROWS:
        return False
    if total_count < len(branch_policies):
        return False
    return all(_github_environment_deployment_branch_policy_row_is_safe(row) for row in branch_policies)


def _github_environment_deployment_branch_policy_refresh_summary(origin_uri: str, payload: dict[str, Any]) -> str:
    path_info = _github_environment_deployment_branch_policy_path_info(origin_uri)
    repo, environment, policy_id = path_info if path_info is not None else ("repository", "environment", 0)
    safe_environment = _safe_public_text(environment, limit=200) or "environment"
    name = _safe_public_text(payload.get("name"), limit=120)
    policy_type = _safe_public_text(payload.get("type"), limit=40).lower()
    return _bounded_refresh_summary(
        "; ".join([
            f"GitHub environment deployment branch policy for {repo}",
            f"environment: {safe_environment}",
            f"policy #{policy_id}: {name}; type: {policy_type}",
        ])
    )


def _github_environment_deployment_branch_policies_refresh_summary(origin_uri: str, payload: dict[str, Any]) -> str:
    path_info = _github_environment_deployment_branch_policies_path_info(origin_uri)
    repo, environment = path_info if path_info is not None else ("repository", "environment")
    raw_policies = payload.get("branch_policies")
    branch_policies = raw_policies if isinstance(raw_policies, list) else []
    total_count = _safe_optional_nonnegative_int(payload.get("total_count"))
    visible_count = total_count if total_count is not None else len(branch_policies)
    safe_environment = _safe_public_text(environment, limit=200) or "environment"
    parts = [
        f"GitHub environment deployment branch policies for {repo}",
        f"environment: {safe_environment}",
        f"policy count: {visible_count}",
    ]
    for row in branch_policies[:5]:
        if not _github_environment_deployment_branch_policy_row_is_safe(row):
            continue
        policy_id = _safe_optional_nonnegative_int(row.get("id")) or 0
        name = _safe_public_text(row.get("name"), limit=120)
        policy_type = _safe_public_text(row.get("type"), limit=40).lower()
        parts.append(f"policy #{policy_id}: {name}; type: {policy_type}")
    return _bounded_refresh_summary("; ".join(parts))


def _github_environment_deployment_branch_policy_fetch_origin_from_origin_text(origin_text: str) -> str:
    prefix = "github environment deployment branch policy "
    text = str(origin_text or "").strip()
    if not text.lower().startswith(prefix):
        return ""
    remainder = text[len(prefix):].strip()
    match = re.fullmatch(r"([A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+) (.+) #([1-9][0-9]*)", remainder)
    if not match:
        return ""
    repo, environment, policy_id = match.groups()
    owner, name = repo.split("/", 1)
    if (
        not _github_repo_path_segment_is_safe(owner)
        or not _github_repo_path_segment_is_safe(name)
        or not _github_environment_name_is_safe(environment)
        or _github_environment_name_has_traversal_segment(environment)
    ):
        return ""
    return f"https://api.github.com/repos/{owner}/{name}/environments/{quote(environment, safe='')}/deployment-branch-policies/{policy_id}"


def _github_environment_deployment_branch_policies_fetch_origin_from_origin_text(origin_text: str) -> str:
    prefix = "github environment deployment branch policies "
    text = str(origin_text or "").strip()
    if not text.lower().startswith(prefix):
        return ""
    remainder = text[len(prefix):].strip()
    match = re.fullmatch(r"([A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+) (.+)", remainder)
    if not match:
        return ""
    repo, environment = match.groups()
    owner, name = repo.split("/", 1)
    if (
        not _github_repo_path_segment_is_safe(owner)
        or not _github_repo_path_segment_is_safe(name)
        or not _github_environment_name_is_safe(environment)
    ):
        return ""
    return f"https://api.github.com/repos/{owner}/{name}/environments/{quote(environment, safe='')}/deployment-branch-policies"


