_GITHUB_MILESTONES_MAX_ROWS = 100
_GITHUB_MILESTONE_STATES = {"open", "closed"}


def _github_milestones_public_origin(origin_uri: str) -> str:
    repo = _github_milestones_path_repo(origin_uri)
    return f"github milestones {repo}" if repo else ""


def _github_milestones_path_repo(origin_uri: str) -> str:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return ""
    if parts.netloc.strip() != "api.github.com":
        return ""
    path = parts.path.split("/")
    if (
        len(path) != 5
        or path[0] != ""
        or path[1] != "repos"
        or path[4] != "milestones"
        or not _github_repo_path_segment_is_safe(path[2])
        or not _github_repo_path_segment_is_safe(path[3])
    ):
        return ""
    return f"{path[2]}/{path[3]}"


def _github_milestones_final_url_matches_origin(origin_uri: str, final_url: Any) -> bool:
    if not isinstance(final_url, str):
        return False
    origin_repo = _github_milestones_path_repo(origin_uri)
    if not origin_repo:
        return False
    try:
        origin_parts = urlsplit(origin_uri)
        final_parts = urlsplit(final_url)
    except ValueError:
        return False
    origin_path = origin_parts.path.split("/")
    if (
        origin_parts.scheme != "https"
        or origin_parts.netloc != "api.github.com"
        or origin_parts.query
        or origin_parts.fragment
        or final_parts.scheme != "https"
        or final_parts.netloc != "api.github.com"
        or final_parts.query
        or final_parts.fragment
        or len(origin_path) != 5
        or origin_path[0] != ""
        or origin_path[1] != "repos"
        or origin_path[4] != "milestones"
        or not _github_repo_path_segment_is_safe(origin_path[2])
        or not _github_repo_path_segment_is_safe(origin_path[3])
    ):
        return False
    expected_path = f"/repos/{origin_path[2]}/{origin_path[3]}/milestones"
    expected_origin = urlunsplit(("https", "api.github.com", expected_path, "", ""))
    return origin_uri == expected_origin and final_url == expected_origin and _github_milestones_path_repo(final_url) == origin_repo


def _github_milestones_route_path_matches(origin_uri: str) -> bool:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return False

    def _segments_match(path_segments: list[str]) -> bool:
        lowered = [segment.lower() for segment in path_segments]
        return (
            len(path_segments) >= 5
            and path_segments[0] == ""
            and lowered[1] == "repos"
            and lowered[4].startswith("milestones")
        )

    raw_path = parts.path.split("/")
    if _segments_match(raw_path):
        return True
    decoded_path = unquote(parts.path).split("/")
    if _segments_match(decoded_path):
        return True
    return False


def _github_milestones_path_matches(origin_uri: str) -> bool:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return False
    if (parts.hostname or "").strip().lower() != "api.github.com":
        return False
    return _github_milestones_route_path_matches(origin_uri)


