def _github_actions_org_variables_selected_repository_row_is_safe(row: Any) -> bool:
    if not isinstance(row, dict):
        return False
    if set(row) - {"id", "name"}:
        return False
    repo_id = _safe_optional_nonnegative_int(row.get("id"))
    if repo_id is None or repo_id <= 0:
        return False
    if not _github_repo_path_segment_is_safe(str(row.get("name") or "")):
        return False
    for raw_value in (row.get("id"), row.get("name")):
        if _refresh_value_is_blocked(raw_value):
            return False
    return True


def _github_actions_org_variable_value_has_blocked_metadata(value: Any) -> bool:
    if isinstance(value, dict):
        for raw_key, raw_value in value.items():
            if not isinstance(raw_key, str):
                return True
            if _refresh_value_is_blocked(raw_key) or _UNSAFE_KEY_RE.search(raw_key):
                return True
            if _github_actions_org_variable_value_has_blocked_metadata(raw_value):
                return True
        return False
    if isinstance(value, list):
        return any(_github_actions_org_variable_value_has_blocked_metadata(item) for item in value)
    if isinstance(value, _PUBLIC_SCALAR_TYPES):
        text = str(value)
        return bool(
            _refresh_value_is_blocked(value)
            or _UNSAFE_VALUE_RE.search(text)
            or _UNSAFE_PUBLIC_VALUE_RE.search(text)
        )
    return value is not None


def _github_actions_org_variable_row_is_safe(row: Any) -> bool:
    if not isinstance(row, dict):
        return False
    if set(row) - (_GITHUB_ACTIONS_ORG_VARIABLES_ALLOWED_ROW_KEYS | _GITHUB_ACTIONS_ORG_VARIABLES_IGNORED_ROW_KEYS):
        return False
    if not _github_actions_variable_name_is_safe(row.get("name")):
        return False
    visibility = row.get("visibility")
    if visibility is not None:
        visibility_text = _safe_public_text(visibility, limit=40).lower()
        if visibility_text not in _GITHUB_ACTIONS_ORG_VARIABLES_VISIBILITIES or visibility_text != str(visibility).strip().lower():
            return False
    selected_count = row.get("selected_repositories_count")
    if selected_count is not None:
        safe_selected_count = _safe_optional_nonnegative_int(selected_count)
        if safe_selected_count is None:
            return False
    selected_repositories = row.get("selected_repositories")
    if selected_repositories is not None:
        if not isinstance(selected_repositories, list) or len(selected_repositories) > _GITHUB_ACTIONS_ORG_VARIABLES_SELECTED_REPOSITORIES_MAX_ROWS:
            return False
        if not all(_github_actions_org_variables_selected_repository_row_is_safe(repo) for repo in selected_repositories):
            return False
        safe_selected_count = _safe_optional_nonnegative_int(row.get("selected_repositories_count"))
        if safe_selected_count is not None and safe_selected_count < len(selected_repositories):
            return False
    for field in ("created_at", "updated_at"):
        raw_timestamp = row.get(field)
        if raw_timestamp is not None and not _safe_iso_timestamp(raw_timestamp):
            return False
    public_row = {key: value for key, value in row.items() if key in _GITHUB_ACTIONS_ORG_VARIABLES_ALLOWED_ROW_KEYS}
    return not _github_actions_org_variable_value_has_blocked_metadata(public_row)


def _json_payload_is_github_actions_org_variables_metadata(origin_uri: str, payload: Any) -> bool:
    if not _github_actions_org_variables_path_org(origin_uri):
        return False
    if not isinstance(payload, dict):
        return False
    if _json_payload_is_feed(payload) or set(payload) != _GITHUB_ACTIONS_ORG_VARIABLES_ALLOWED_TOP_LEVEL_KEYS:
        return False
    total_count = _safe_optional_nonnegative_int(payload.get("total_count"))
    variables = payload.get("variables")
    if total_count is None or not isinstance(variables, list) or len(variables) > _GITHUB_ACTIONS_ORG_VARIABLES_MAX_ROWS:
        return False
    if total_count < len(variables):
        return False
    return all(_github_actions_org_variable_row_is_safe(row) for row in variables)


def _github_actions_org_variables_refresh_summary(origin_uri: str, payload: dict[str, Any]) -> str:
    org = _github_actions_org_variables_path_org(origin_uri) or "organization"
    raw_variables = payload.get("variables")
    variables = raw_variables if isinstance(raw_variables, list) else []
    total_count = _safe_optional_nonnegative_int(payload.get("total_count"))
    visible_count = total_count if total_count is not None else len(variables)
    parts = [f"GitHub Actions organization variables for {org}", f"variable count: {visible_count}"]
    for row in variables[:5]:
        if not _github_actions_org_variable_row_is_safe(row):
            continue
        name = _safe_public_text(row.get("name"), limit=120)
        row_parts = [f"variable: {name}"]
        visibility = _safe_public_text(row.get("visibility"), limit=40).lower()
        if visibility in _GITHUB_ACTIONS_ORG_VARIABLES_VISIBILITIES:
            row_parts.append(f"visibility: {visibility}")
        selected_count = _safe_optional_nonnegative_int(row.get("selected_repositories_count"))
        if selected_count is not None:
            row_parts.append(f"selected repository count: {selected_count}")
        selected_repositories = row.get("selected_repositories")
        if isinstance(selected_repositories, list):
            for repo in selected_repositories[:3]:
                if not _github_actions_org_variables_selected_repository_row_is_safe(repo):
                    continue
                repo_name = _safe_public_text(repo.get("name"), limit=120)
                repo_id = _safe_optional_nonnegative_int(repo.get("id"))
                if repo_name and repo_id is not None:
                    row_parts.append(f"selected repository: {repo_name} (id {repo_id})")
        created = _safe_iso_timestamp(row.get("created_at")) if row.get("created_at") is not None else ""
        updated = _safe_iso_timestamp(row.get("updated_at")) if row.get("updated_at") is not None else ""
        if created:
            row_parts.append(f"created: {created}")
        if updated:
            row_parts.append(f"updated: {updated}")
        parts.append("; ".join(row_parts))
    return _bounded_refresh_summary("; ".join(parts))


