def _github_org_path_segment_is_safe(value: Any) -> bool:
    if not isinstance(value, str):
        return False
    return re.fullmatch(r"[A-Za-z0-9](?:[A-Za-z0-9-]{0,37}[A-Za-z0-9])?", value) is not None


def _github_actions_org_secrets_query_fragment_has_auth(parts: Any) -> bool:
    query_fragment = "&".join(value for value in (getattr(parts, "query", ""), getattr(parts, "fragment", "")) if value)
    if not query_fragment:
        return False
    lowered = unquote(query_fragment).lower()
    return bool(_REFRESH_SITEMAP_BLOCKED_QUERY_VALUE_RE.search(lowered) or "access_token" in lowered)


