def _github_dependabot_org_secrets_legacy_route_public_context(*values: Any) -> bool:
    for value in values:
        if not isinstance(value, _PUBLIC_SCALAR_TYPES):
            continue
        text = str(value or "").strip()
        if not text:
            continue
        if _safe_github_dependabot_org_secrets_origin_text(text) or (
            _github_dependabot_org_secrets_route_path_matches(text)
            and not _github_dependabot_org_secrets_public_key_route_path_matches(text)
        ):
            return True
        normalized = unquote(text).lower()
        if (
            "api.github.com" in normalized
            and "/orgs/" in normalized
            and "/dependabot/secrets" in normalized
            and "/dependabot/secrets/public-key" not in normalized
        ):
            return True
    return False


