def _safe_github_dependabot_org_secrets_summary_with_drop(value: Any, *, limit: int = 1_200) -> tuple[str, int]:
    if not isinstance(value, _PUBLIC_SCALAR_TYPES):
        return "", 1 if _is_present_public_value(value) else 0
    text = _safe_text(value, limit=limit)
    if not text or _UNSAFE_VALUE_RE.search(text) or _UNSAFE_PUBLIC_VALUE_RE.search(text):
        return "", 1
    lowered = text.lower()
    if "api.github.com" in lowered or "https://" in lowered or "/orgs/" in lowered:
        return "", 1
    return text, 0


