def _github_workflow_run_pending_deployment_reviewer_label(row: Any) -> tuple[str, str] | None:
    if not isinstance(row, dict):
        return None
    reviewer_type = row.get("type")
    reviewer = row.get("reviewer")
    if reviewer_type not in {"User", "Team", "App"} or not isinstance(reviewer, dict):
        return None
    if reviewer_type == "User":
        label = reviewer.get("login")
        if not _github_comment_login_is_safe(label):
            return None
        return "user", _safe_public_text(label, limit=80)
    label = reviewer.get("slug") or reviewer.get("name") or reviewer.get("login")
    if not _github_workflow_run_pending_deployment_reviewer_label_is_safe(label):
        return None
    return reviewer_type.lower(), _safe_public_text(label, limit=80)


def _github_workflow_run_pending_deployment_row_is_safe(row: Any) -> bool:
    if not isinstance(row, dict):
        return False
    if not _github_workflow_run_pending_deployment_environment_is_safe(row.get("environment")):
        return False
    if not _github_workflow_run_pending_deployment_wait_timer_is_safe(row.get("wait_timer")):
        return False
    if not _github_workflow_run_pending_deployment_status_is_safe(row.get("status")):
        return False
    raw_created = row.get("created_at")
    if _is_present_public_value(raw_created) and not _safe_iso_timestamp(raw_created):
        return False
    reviewers = row.get("reviewers")
    if _is_present_public_value(reviewers):
        if not isinstance(reviewers, list) or len(reviewers) > 30:
            return False
        if not all(_github_workflow_run_pending_deployment_reviewer_label(reviewer) for reviewer in reviewers):
            return False
    return True


