def _github_actions_runner_group_value_has_blocked_metadata(value: Any) -> bool:
    if isinstance(value, dict):
        for raw_key, raw_value in value.items():
            if not isinstance(raw_key, str):
                return True
            if _refresh_value_is_blocked(raw_key) or _UNSAFE_KEY_RE.search(raw_key):
                return True
            if _github_actions_runner_group_value_has_blocked_metadata(raw_value):
                return True
        return False
    if isinstance(value, list):
        return any(_github_actions_runner_group_value_has_blocked_metadata(item) for item in value)
    if isinstance(value, _PUBLIC_SCALAR_TYPES):
        text = str(value)
        return bool(
            _refresh_value_is_blocked(value)
            or _UNSAFE_VALUE_RE.search(text)
            or _UNSAFE_PUBLIC_VALUE_RE.search(text)
        )
    return False


def _github_actions_runner_group_name_is_safe(value: Any) -> bool:
    if not isinstance(value, str):
        return False
    name = value.strip()
    if not name or name != value or len(name) > 120:
        return False
    if _refresh_value_is_blocked(name):
        return False
    return bool(re.fullmatch(r"[A-Za-z0-9_. -]{1,120}", name))


def _github_actions_runner_group_workflow_is_safe(value: Any) -> bool:
    if not isinstance(value, str):
        return False
    workflow = value.strip()
    if not workflow or workflow != value or len(workflow) > 160:
        return False
    lowered = workflow.lower()
    if (
        _refresh_value_is_blocked(workflow)
        or "://" in lowered
        or lowered.startswith(("/", "\\"))
        or "\\" in workflow
        or ".." in workflow.split("/")
        or "//" in workflow
        or any(marker in workflow for marker in ("?", "#", "<", ">", "|", "\x00"))
    ):
        return False
    return bool(re.fullmatch(r"[A-Za-z0-9._-][A-Za-z0-9._/@-]{0,159}", workflow))


def _github_actions_runner_group_row_is_safe(row: Any) -> bool:
    if not isinstance(row, dict):
        return False
    group_id = _safe_optional_nonnegative_int(row.get("id"))
    if group_id is None or group_id <= 0:
        return False
    if not _github_actions_runner_group_name_is_safe(row.get("name")):
        return False
    visibility = row.get("visibility")
    if visibility is not None:
        visibility_text = _safe_public_text(visibility, limit=40).lower()
        if visibility_text not in _GITHUB_ACTIONS_RUNNER_GROUP_VISIBILITIES or visibility_text != str(visibility).strip().lower():
            return False
    for key in _GITHUB_ACTIONS_RUNNER_GROUP_ALLOWED_BOOL_FIELDS:
        if key in row and not isinstance(row.get(key), bool):
            return False
    selected_workflows = row.get("selected_workflows")
    if selected_workflows is not None:
        if not isinstance(selected_workflows, list) or len(selected_workflows) > 20:
            return False
        if not all(_github_actions_runner_group_workflow_is_safe(workflow) for workflow in selected_workflows):
            return False
    for raw_value in (row.get("id"), row.get("name"), row.get("visibility")):
        if _refresh_value_is_blocked(raw_value):
            return False
    return True


