def _github_actions_runner_group_repositories_value_has_blocked_metadata(value: Any) -> bool:
    if isinstance(value, dict):
        for raw_key, raw_value in value.items():
            if not isinstance(raw_key, str):
                return True
            if _refresh_value_is_blocked(raw_key) or _UNSAFE_KEY_RE.search(raw_key):
                return True
            if _github_actions_runner_group_repositories_value_has_blocked_metadata(raw_value):
                return True
        return False
    if isinstance(value, list):
        return any(_github_actions_runner_group_repositories_value_has_blocked_metadata(item) for item in value)
    if isinstance(value, _PUBLIC_SCALAR_TYPES):
        text = str(value)
        return bool(
            _refresh_value_is_blocked(value)
            or _UNSAFE_VALUE_RE.search(text)
            or _UNSAFE_PUBLIC_VALUE_RE.search(text)
        )
    return False


