def _github_actions_runner_group_repository_name_is_safe(value: Any) -> bool:
    if not isinstance(value, str):
        return False
    name = value.strip()
    if not name or name != value or len(name) > 100:
        return False
    if _refresh_value_is_blocked(name) or "://" in name or "/" in name or "\\" in name or ".." in name:
        return False
    return bool(re.fullmatch(r"[A-Za-z0-9_.-]{1,100}", name))


def _github_actions_runner_group_repository_full_name_is_safe(value: Any) -> bool:
    if not isinstance(value, str):
        return False
    full_name = value.strip()
    if not full_name or full_name != value or len(full_name) > 200:
        return False
    if _refresh_value_is_blocked(full_name) or "://" in full_name or "\\" in full_name:
        return False
    parts = full_name.split("/")
    if len(parts) != 2:
        return False
    return all(_github_repo_path_segment_is_safe(part) for part in parts)


def _github_actions_runner_group_repositories_ignored_value_is_safe(value: Any, *, allowed_keys: set[str] | None = None) -> bool:
    if isinstance(value, dict):
        if len(value) > 100:
            return False
        if allowed_keys is not None and set(value) - allowed_keys:
            return False
        for raw_key, raw_value in value.items():
            if not isinstance(raw_key, str):
                return False
            if raw_key == "temp_clone_token":
                if raw_value not in (None, ""):
                    return False
                continue
            if allowed_keys is None and (
                _refresh_value_is_blocked(raw_key)
                or _UNSAFE_VALUE_RE.search(raw_key)
                or _UNSAFE_PUBLIC_VALUE_RE.search(raw_key)
            ):
                return False
            if not _github_actions_runner_group_repositories_ignored_value_is_safe(raw_value):
                return False
        return True
    if isinstance(value, list):
        return len(value) <= 100 and all(
            _github_actions_runner_group_repositories_ignored_value_is_safe(item) for item in value
        )
    if value is None or isinstance(value, bool):
        return True
    if isinstance(value, int):
        return 0 <= value <= 10**18
    if isinstance(value, float):
        return math.isfinite(value)
    if isinstance(value, str):
        if len(value) > 2000:
            return False
        return not (
            _refresh_value_is_blocked(value)
            or _UNSAFE_VALUE_RE.search(value)
            or _UNSAFE_PUBLIC_VALUE_RE.search(value)
        )
    return False


def _github_actions_runner_group_repository_public_row(origin_uri: str, row: Any) -> dict[str, Any] | None:
    info = _github_actions_runner_group_repositories_path_info(origin_uri)
    if info is None or not isinstance(row, dict):
        return None
    if set(row) - _GITHUB_ACTIONS_RUNNER_GROUP_REPOSITORIES_ALLOWED_ROW_KEYS_WITH_IGNORED:
        return None
    for key, value in row.items():
        if key in _GITHUB_ACTIONS_RUNNER_GROUP_REPOSITORIES_ALLOWED_ROW_KEYS:
            continue
        if key == "owner":
            if not _github_actions_runner_group_repositories_ignored_value_is_safe(
                value, allowed_keys=_GITHUB_ACTIONS_RUNNER_GROUP_REPOSITORIES_ALLOWED_OWNER_KEYS
            ):
                return None
        elif key == "permissions":
            if not _github_actions_runner_group_repositories_ignored_value_is_safe(
                value, allowed_keys=_GITHUB_ACTIONS_RUNNER_GROUP_REPOSITORIES_ALLOWED_PERMISSIONS_KEYS
            ):
                return None
            if not isinstance(value, dict) or not all(isinstance(item, bool) for item in value.values()):
                return None
        elif key == "license" and value is not None:
            if not _github_actions_runner_group_repositories_ignored_value_is_safe(
                value, allowed_keys=_GITHUB_ACTIONS_RUNNER_GROUP_REPOSITORIES_ALLOWED_LICENSE_KEYS
            ):
                return None
        elif key == "temp_clone_token":
            if value not in (None, ""):
                return None
        elif key == "template_repository":
            if value is not None and _github_actions_runner_group_repository_public_row(origin_uri, value) is None:
                return None
        elif not _github_actions_runner_group_repositories_ignored_value_is_safe(value):
            return None
    repository_id = _safe_optional_nonnegative_int(row.get("id"))
    if repository_id is None or repository_id <= 0:
        return None
    name = row.get("name")
    full_name = row.get("full_name")
    if not _github_actions_runner_group_repository_name_is_safe(name):
        return None
    if not _github_actions_runner_group_repository_full_name_is_safe(full_name):
        return None
    org, _runner_group_id = info
    full_name_org, full_name_repo = str(full_name).split("/", 1)
    if full_name_org != org or full_name_repo != name:
        return None
    public_row: dict[str, Any] = {"id": repository_id, "name": name, "full_name": full_name}
    if "private" in row:
        if not isinstance(row.get("private"), bool):
            return None
        public_row["private"] = row["private"]
    return public_row


def _github_actions_runner_group_repository_row_is_safe(row: Any, *, origin_uri: str = "") -> bool:
    if origin_uri:
        return _github_actions_runner_group_repository_public_row(origin_uri, row) is not None
    if not isinstance(row, dict) or set(row) - _GITHUB_ACTIONS_RUNNER_GROUP_REPOSITORIES_ALLOWED_ROW_KEYS:
        return False
    if _github_actions_runner_group_repositories_value_has_blocked_metadata(row):
        return False
    repository_id = _safe_optional_nonnegative_int(row.get("id"))
    if repository_id is None or repository_id <= 0:
        return False
    if not _github_actions_runner_group_repository_name_is_safe(row.get("name")):
        return False
    if not _github_actions_runner_group_repository_full_name_is_safe(row.get("full_name")):
        return False
    if "private" in row and not isinstance(row.get("private"), bool):
        return False
    return True


def _json_payload_is_github_actions_runner_group_repositories_metadata(origin_uri: str, payload: Any) -> bool:
    if _github_actions_runner_group_repositories_path_info(origin_uri) is None:
        return False
    if not isinstance(payload, dict):
        return False
    if _json_payload_is_feed(payload) or any(key in payload for key in ("version", "items")):
        return False
    if set(payload) != _GITHUB_ACTIONS_RUNNER_GROUP_REPOSITORIES_ALLOWED_TOP_LEVEL_KEYS:
        return False
    total_count = _safe_optional_nonnegative_int(payload.get("total_count"))
    repositories = payload.get("repositories")
    if (
        total_count is None
        or not isinstance(repositories, list)
        or len(repositories) > _GITHUB_ACTIONS_RUNNER_GROUP_REPOSITORIES_MAX_ROWS
        or total_count < len(repositories)
    ):
        return False
    return all(
        _github_actions_runner_group_repository_public_row(origin_uri, row) is not None
        for row in repositories
    )


def _github_actions_runner_group_repositories_refresh_summary(origin_uri: str, payload: dict[str, Any]) -> str:
    info = _github_actions_runner_group_repositories_path_info(origin_uri)
    org = info[0] if info is not None else "organization"
    runner_group_id = info[1] if info is not None else 0
    total_count = _safe_optional_nonnegative_int(payload.get("total_count")) or 0
    raw_rows = payload.get("repositories")
    rows = raw_rows if isinstance(raw_rows, list) else []
    parts = [
        f"GitHub Actions runner group repositories for {org} group {runner_group_id}",
        f"repository count: {total_count}",
    ]
    for row in rows[:5]:
        public_row = _github_actions_runner_group_repository_public_row(origin_uri, row)
        if public_row is None:
            continue
        full_name = _safe_public_text(public_row.get("full_name"), limit=200)
        repository_id = _safe_optional_nonnegative_int(public_row.get("id")) or 0
        visibility = "private" if public_row.get("private") is True else "public" if public_row.get("private") is False else "unknown"
        parts.append(f"{full_name} (id {repository_id}, {visibility})")
    return _bounded_refresh_summary("; ".join(parts))


