def _github_actions_single_secret_path_info(origin_uri: str) -> tuple[str, str] | None:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return None
    if parts.scheme != "https" or parts.netloc.strip() != "api.github.com":
        return None
    path = parts.path.split("/")
    if (
        len(path) != 7
        or path[0] != ""
        or path[1] != "repos"
        or path[4] != "actions"
        or path[5] != "secrets"
        or not _github_repo_path_segment_is_safe(path[2])
        or not _github_repo_path_segment_is_safe(path[3])
        or not _github_actions_secret_name_is_safe(path[6])
    ):
        return None
    return f"{path[2]}/{path[3]}", path[6]


def _github_actions_single_secret_safe_origin(origin_uri: str) -> str:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return ""
    if parts.scheme != "https":
        return ""
    if parts.netloc != "api.github.com" or parts.query or parts.fragment:
        return ""
    path = parts.path.split("/")
    if (
        len(path) != 7
        or path[0] != ""
        or path[1] != "repos"
        or path[4] != "actions"
        or path[5] != "secrets"
        or not _github_repo_path_segment_is_safe(path[2])
        or not _github_repo_path_segment_is_safe(path[3])
        or not _github_actions_secret_name_is_safe(path[6])
    ):
        return ""
    return urlunsplit(("https", "api.github.com", parts.path, "", ""))


def _github_actions_single_secret_origin_from_metadata(repo_path: str, secret_name: str) -> str:
    repo_path = str(repo_path or "")
    secret_name = str(secret_name or "")
    if not _github_repo_path_is_safe(repo_path) or not _github_actions_secret_name_is_safe(secret_name):
        return ""
    owner, repo = repo_path.split("/", 1)
    return f"https://api.github.com/repos/{owner}/{repo}/actions/secrets/{secret_name}"


def _github_actions_single_secret_info_from_public_origin(origin_text: str) -> tuple[str, str] | None:
    prefix = "github actions private name "
    text = str(origin_text or "").strip()
    if not text.lower().startswith(prefix):
        return None
    remainder = text[len(prefix):]
    try:
        repo_path, secret_name = remainder.rsplit(" ", 1)
    except ValueError:
        return None
    if not _github_repo_path_is_safe(repo_path) or not _github_actions_secret_name_is_safe(secret_name):
        return None
    return repo_path, secret_name


def _github_actions_single_secret_route_path_matches(origin_uri: str) -> bool:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return False
    if (parts.hostname or "").strip().lower() != "api.github.com":
        return False

    def _segments_match(path_segments: list[str]) -> bool:
        lowered = [segment.lower() for segment in path_segments]
        return (
            len(path_segments) >= 7
            and path_segments[0] == ""
            and lowered[1] == "repos"
            and lowered[4] == "actions"
            and lowered[5] == "secrets"
            and not lowered[6].startswith("public-key")
        )

    raw_path = parts.path.split("/")
    if _segments_match(raw_path):
        return True
    decoded_path = unquote(parts.path).split("/")
    if _segments_match(decoded_path):
        return True
    return any(segment.lower().startswith("secrets%") for segment in raw_path)


def _github_actions_secret_name_is_safe(value: Any) -> bool:
    if not isinstance(value, str):
        return False
    name = value.strip()
    if not name or name != value:
        return False
    if not re.fullmatch(r"[A-Z][A-Z0-9_]{0,99}", name):
        return False
    if _refresh_value_is_blocked(name) or _UNSAFE_KEY_RE.search(name):
        return False
    return True


def _github_actions_secret_row_is_safe(row: Any) -> bool:
    if not isinstance(row, dict):
        return False
    if not _github_actions_secret_name_is_safe(row.get("name")):
        return False
    for field in ("created_at", "updated_at"):
        raw_timestamp = row.get(field)
        if raw_timestamp is not None and not _safe_iso_timestamp(raw_timestamp):
            return False
    for raw_value in (row.get("name"), row.get("created_at"), row.get("updated_at")):
        if _refresh_value_is_blocked(raw_value):
            return False
    return True


