def _safe_github_actions_org_secrets_public_key_summary_with_drop(value: Any, *, limit: int = 1_200) -> tuple[str, int]:
    if not isinstance(value, _PUBLIC_SCALAR_TYPES):
        return "", 1 if value is not None else 0
    text = str(value).strip()
    match = re.fullmatch(
        r"GitHub Actions organization secrets public key for ([A-Za-z0-9][A-Za-z0-9-]{0,38}); key id: ([0-9]{1,40})",
        text,
    )
    if not match:
        return "", 1 if text else 0
    org, key_id = match.groups()
    if not _github_org_path_segment_is_safe(org) or not _github_actions_public_key_id_is_safe(key_id):
        return "", 1
    return _safe_text(text, limit=limit), 0


