def _github_issue_events_path_info(origin_uri: str) -> tuple[str, int] | None:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return None
    if parts.scheme != "https" or not _github_https_authority_is_exact(origin_uri, "api.github.com"):
        return None
    path = parts.path.split("/")
    if (
        len(path) != 7
        or path[0] != ""
        or path[1] != "repos"
        or not _github_repo_path_segment_is_safe(path[2])
        or not _github_repo_path_segment_is_safe(path[3])
        or path[4] != "issues"
        or not re.fullmatch(r"[1-9][0-9]*", path[5])
        or path[6] != "events"
    ):
        return None
    return f"{path[2]}/{path[3]}", int(path[5])


def _github_issue_events_path_matches(origin_uri: str) -> bool:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return False
    if (parts.hostname or "").strip().lower() != "api.github.com":
        return False

    def _matches_issue_events_shape(raw_path: str) -> bool:
        path = raw_path.split("/")
        lowered = [segment.lower() for segment in path]
        return len(path) >= 7 and path[0] == "" and lowered[1] == "repos" and lowered[4] == "issues" and lowered[6].startswith("events")

    return _matches_issue_events_shape(parts.path) or _matches_issue_events_shape(unquote(parts.path))


def _github_issue_events_final_url_matches_origin(origin_uri: str, final_url: Any) -> bool:
    origin_info = _github_issue_events_path_info(origin_uri)
    if origin_info is None or not isinstance(final_url, str):
        return False
    if not _github_https_authority_is_exact(final_url, "api.github.com"):
        return False
    return final_url == origin_uri and _github_issue_events_path_info(final_url) == origin_info


