def _github_commit_comments_path_info(origin_uri: str) -> tuple[str, str] | None:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return None
    if (parts.hostname or "").strip().lower() != "api.github.com":
        return None
    path = parts.path.split("/")
    lowered = [segment.lower() for segment in path]
    if (
        len(path) != 7
        or path[0] != ""
        or lowered[1] != "repos"
        or not _github_repo_path_segment_is_safe(path[2])
        or not _github_repo_path_segment_is_safe(path[3])
        or lowered[4] != "commits"
        or not re.fullmatch(r"[A-Fa-f0-9]{40}", path[5])
        or lowered[6] != "comments"
    ):
        return None
    return f"{path[2]}/{path[3]}", path[5].lower()


def _github_commit_comments_path_matches(origin_uri: str) -> bool:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return False
    if not (parts.hostname or "").strip():
        return False

    def _matches_commit_comments_shape(raw_path: str) -> bool:
        path = raw_path.split("/")
        lowered = [segment.lower() for segment in path]
        return (
            len(path) >= 7
            and path[0] == ""
            and len(lowered) > 6
            and lowered[1] == "repos"
            and lowered[4] == "commits"
            and lowered[6].startswith("comments")
        )

    return _matches_commit_comments_shape(parts.path) or _matches_commit_comments_shape(unquote(parts.path))


def _github_commit_comments_final_url_matches_origin(origin_uri: str, final_url: Any) -> bool:
    if not isinstance(final_url, str):
        return False
    origin_info = _github_commit_comments_path_info(origin_uri)
    if origin_info is None or _github_commit_comments_path_info(final_url) != origin_info:
        return False
    return (
        _github_https_authority_is_exact(origin_uri, "api.github.com")
        and _github_https_authority_is_exact(final_url, "api.github.com")
        and final_url == origin_uri
    )


