    size = _safe_optional_nonnegative_int(payload.get("size"))
    parts = [f"GitHub license for {repo}", f"license key: {key}", f"license: {name}", f"spdx: {spdx}"]
    if path:
        parts.append(f"path: {path}")
    if size is not None:
        parts.append(f"size: {size}")
    if sha:
        parts.append(f"sha: {sha}")
