    if ".." in text or "//" in text or text.startswith(("/", ".")) or text.endswith(("/", ".")):
        return False
    return bool(re.fullmatch(r"[A-Za-z0-9][A-Za-z0-9 ._()+,/@-]{0," + str(limit - 1) + r"}", text))


