def _safe_github_dependabot_alerts_origin_text(value: Any) -> str:
    text = _safe_public_text(value, limit=240)
    match = re.fullmatch(
        r"github dependabot alerts ([A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+)",
        text,
        flags=re.IGNORECASE,
    )
    if not match:
        return ""
    owner, repo = match.group(1).split("/", 1)
    if not _github_repo_path_segment_is_safe(owner) or not _github_repo_path_segment_is_safe(repo):
        return ""
    return f"github dependabot alerts {owner}/{repo}"


