def _github_dependabot_single_alert_public_origin(origin_uri: str) -> str:
    info = _github_dependabot_single_alert_path_info(origin_uri)
    if info is None:
        return ""
    repo, number = info
    return f"github dependabot alert {repo} #{number}"


def _github_dependabot_single_alert_origin_is_exact_fetch_origin(origin_uri: str) -> bool:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return False
    return (
        parts.scheme == "https"
        and parts.netloc == "api.github.com"
        and not parts.query
        and not parts.fragment
        and _github_dependabot_single_alert_path_info(origin_uri) is not None
    )


def _safe_github_dependabot_single_alert_origin_text(value: Any) -> str:
    text = _safe_public_text(value, limit=240)
    match = re.fullmatch(
        r"github dependabot alert ([A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+) #([1-9][0-9]{0,9})",
        text,
        flags=re.IGNORECASE,
    )
    if not match:
        return ""
    owner, repo = match.group(1).split("/", 1)
    number = int(match.group(2))
    if (
        not _github_repo_path_segment_is_safe(owner)
        or not _github_repo_path_segment_is_safe(repo)
        or not _github_dependabot_alert_number_is_safe(number)
    ):
        return ""
    return f"github dependabot alert {owner}/{repo} #{number}"


def _github_dependabot_single_alert_fetch_origin_from_origin_text(origin_text: str) -> str:
    text = _safe_github_dependabot_single_alert_origin_text(origin_text)
    if not text:
        return ""
    match = re.fullmatch(r"github dependabot alert ([^ ]+) #([0-9]+)", text)
    if not match:
        return ""
    return f"https://api.github.com/repos/{match.group(1)}/dependabot/alerts/{int(match.group(2))}"


def _github_dependabot_single_alert_unsafe_raw_origin_candidate(origin_uri: Any) -> bool:
    text = str(origin_uri or "").strip()
    if not text or _safe_github_dependabot_single_alert_origin_text(text):
        return False
    if _github_dependabot_single_alert_route_path_matches(text):
        return not _github_dependabot_single_alert_origin_is_exact_fetch_origin(text)
    if not _github_dependabot_alerts_path_matches(text):
        return False
    try:
        parts = urlsplit(text)
    except ValueError:
        return False
    for raw_path in {parts.path, unquote(parts.path)}:
        path = raw_path.split("/")
        lowered = [segment.lower() for segment in path]
        if len(path) < 7 or path[0] != "" or lowered[1] != "repos":
            continue
        for index in range(4, len(path) - 2):
            if lowered[index] != "dependabot" or not lowered[index + 1].startswith("alerts"):
                continue
            if any(segment.isdigit() for segment in path[index + 2 :]):
                return True
    return False


_GITHUB_DEPENDABOT_ALERT_STATES = {"auto_dismissed", "dismissed", "fixed", "open"}
_GITHUB_DEPENDABOT_ALERT_SEVERITIES = {"low", "medium", "moderate", "high", "critical"}
_GITHUB_DEPENDABOT_ALERTS_MAX_ROWS = 100


def _github_dependabot_alert_number_is_safe(value: Any) -> bool:
    return not isinstance(value, bool) and isinstance(value, int) and 0 < value <= 10_000_000_000


def _github_dependabot_alert_state(value: Any) -> str:
    if isinstance(value, str) and value in _GITHUB_DEPENDABOT_ALERT_STATES:
        return value
    return ""


def _github_dependabot_alert_text_is_safe(value: Any, *, limit: int = 200) -> str:
    if not isinstance(value, str):
        return ""
    text = value.strip()
    if not text or text != value:
        return ""
    if _safe_public_text(text, limit=limit) != text or _refresh_value_is_blocked(text):
        return ""
    return text


def _github_dependabot_alert_ecosystem_is_safe(value: Any) -> str:
    text = _github_dependabot_alert_text_is_safe(value, limit=80)
    if not text:
        return ""
    if not re.fullmatch(r"[A-Za-z0-9][A-Za-z0-9._+:-]{0,79}", text):
        return ""
    return text


def _github_dependabot_alert_package_name_is_safe(value: Any) -> str:
    text = _github_dependabot_alert_text_is_safe(value, limit=200)
    if not text:
        return ""
    if not re.fullmatch(r"[A-Za-z0-9@][A-Za-z0-9@./_:+-]{0,199}", text):
        return ""
    return text


def _github_dependabot_alert_manifest_path_is_safe(value: Any) -> str:
    text = _github_dependabot_alert_text_is_safe(value, limit=200)
    if not text or text.startswith("/") or "\\" in text:
        return ""
    if ".." in text.split("/"):
        return ""
    if not re.fullmatch(r"[A-Za-z0-9][A-Za-z0-9._+/@:-]{0,199}", text):
        return ""
    return text


def _github_dependabot_alert_dependency_info(row: dict[str, Any]) -> tuple[str, str, str] | None:
    dependency = row.get("dependency")
    if not isinstance(dependency, dict):
        return None
    package = dependency.get("package")
    if not isinstance(package, dict):
        return None
    ecosystem = _github_dependabot_alert_ecosystem_is_safe(package.get("ecosystem"))
    name = _github_dependabot_alert_package_name_is_safe(package.get("name"))
    manifest = _github_dependabot_alert_manifest_path_is_safe(dependency.get("manifest_path"))
    if not ecosystem or not name or not manifest:
        return None
    return ecosystem, name, manifest


def _github_dependabot_alert_severity(row: dict[str, Any]) -> str:
    for container_name in ("security_advisory", "security_vulnerability"):
        container = row.get(container_name)
        if isinstance(container, dict):
            severity = str(container.get("severity") or "").lower()
            if severity in _GITHUB_DEPENDABOT_ALERT_SEVERITIES:
                return severity
    return ""


def _github_dependabot_alert_ignored_value_is_safe(value: Any) -> bool:
    if isinstance(value, dict):
        return all(
            isinstance(key, str)
            and not _refresh_value_is_blocked(key)
            and _github_dependabot_alert_ignored_value_is_safe(item)
            for key, item in value.items()
        )
    if isinstance(value, list):
        return all(_github_dependabot_alert_ignored_value_is_safe(item) for item in value)
    return not _refresh_value_is_blocked(value)


def _github_dependabot_alert_row_is_safe(row: Any) -> bool:
    if not isinstance(row, dict):
        return False
    allowed_keys = {
        "auto_dismissed_at",
        "created_at",
        "dependency",
        "dismissed_at",
        "dismissed_by",
        "dismissed_comment",
        "dismissed_reason",
        "fixed_at",
        "html_url",
        "number",
        "security_advisory",
        "security_vulnerability",
        "state",
        "url",
        "updated_at",
    }
    if any(key not in allowed_keys for key in row):
        return False
    if not all(_github_dependabot_alert_ignored_value_is_safe(value) for value in row.values()):
        return False
    if not _github_dependabot_alert_number_is_safe(row.get("number")):
        return False
    if not _github_dependabot_alert_state(row.get("state")):
        return False
    if _github_dependabot_alert_dependency_info(row) is None:
        return False
    if not _github_dependabot_alert_severity(row):
        return False
    for field in ("created_at", "updated_at", "dismissed_at", "fixed_at", "auto_dismissed_at"):
        if field in row and row.get(field) is not None and not _safe_iso_timestamp(row.get(field)):
            return False
    return True


def _json_payload_is_github_dependabot_alerts_metadata(origin_uri: str, payload: Any) -> bool:
    if not _github_dependabot_alerts_path_repo(origin_uri):
        return False
    if not isinstance(payload, list) or len(payload) > _GITHUB_DEPENDABOT_ALERTS_MAX_ROWS:
        return False
    return all(_github_dependabot_alert_row_is_safe(row) for row in payload)


def _github_dependabot_alerts_refresh_summary(origin_uri: str, payload: list[Any]) -> str:
    repo = _github_dependabot_alerts_path_repo(origin_uri) or "repository"
    safe_rows = [row for row in payload if _github_dependabot_alert_row_is_safe(row)]
    parts = [f"GitHub Dependabot alerts for {repo}", f"alert count: {len(payload)}"]
    for row in safe_rows[:5]:
        dependency = _github_dependabot_alert_dependency_info(row)
        if dependency is None:
            continue
        ecosystem, name, manifest = dependency
        severity = _github_dependabot_alert_severity(row)
        parts.append(
            "; ".join([
                f"alert #{int(row.get('number'))}: {_safe_public_text(row.get('state'), limit=40)}",
                f"ecosystem: {ecosystem}",
                f"package: {name}",
                f"manifest: {manifest}",
                f"severity: {severity}",
            ])
        )
    return _bounded_refresh_summary("; ".join(parts))


def _github_dependabot_single_alert_payload_url_matches(origin_uri: str, value: Any, *, html: bool = False) -> bool:
    info = _github_dependabot_single_alert_path_info(origin_uri)
    if info is None or not isinstance(value, str) or not value.strip() or value.strip() != value:
        return False
    repo, number = info
    try:
        parts = urlsplit(value)
    except ValueError:
        return False
    if parts.scheme != "https" or parts.query or parts.fragment:
        return False
    if html:
        html_path = f"/{repo}/security/dependabot/{number}"
        return parts.netloc == "github.com" and parts.path == html_path
    return _github_dependabot_single_alert_safe_origin(value) == origin_uri


_GITHUB_DEPENDABOT_SINGLE_ALERT_HOSTILE_KEY_EXCEPTIONS = {
    "description",
    "html_url",
}


def _github_dependabot_single_alert_key_has_hostile_marker(value: Any) -> bool:
    if not isinstance(value, str):
        return True
    if value in _GITHUB_DEPENDABOT_SINGLE_ALERT_HOSTILE_KEY_EXCEPTIONS:
        return False
    return bool(_refresh_value_is_blocked(value) or _UNSAFE_KEY_RE.search(value))


def _github_dependabot_single_alert_payload_has_hostile_marker(value: Any) -> bool:
    if isinstance(value, dict):
        for key, item in value.items():
            if _github_dependabot_single_alert_key_has_hostile_marker(key):
                return True
            if _github_dependabot_single_alert_payload_has_hostile_marker(item):
                return True
        return False
    if isinstance(value, list):
        return any(_github_dependabot_single_alert_payload_has_hostile_marker(item) for item in value)
    if isinstance(value, str):
        return bool(_refresh_value_is_blocked(value) or _UNSAFE_VALUE_RE.search(value))
    return _refresh_value_is_blocked(value)


def _github_dependabot_single_alert_severity_container_is_safe(value: Any) -> bool:
    if not isinstance(value, dict):
        return False
    if "severity" not in value:
        return True
    severity = str(value.get("severity") or "").lower()
    return severity in _GITHUB_DEPENDABOT_ALERT_SEVERITIES


_GITHUB_DEPENDABOT_SINGLE_ALERT_FEED_FALLBACK_KEYS = {
    "content_html",
    "content_text",
    "feed_url",
    "home_page_url",
    "items",
    "summary",
    "title",
    "version",
}


def _github_dependabot_single_alert_payload_has_feed_fallback_marker(payload: dict[str, Any]) -> bool:
    return _json_payload_is_feed(payload) or any(
        key in payload for key in _GITHUB_DEPENDABOT_SINGLE_ALERT_FEED_FALLBACK_KEYS
    )


def _json_payload_is_github_dependabot_single_alert_metadata(origin_uri: str, payload: Any) -> bool:
    info = _github_dependabot_single_alert_path_info(origin_uri)
    if info is None or not isinstance(payload, dict):
        return False
    if _github_dependabot_single_alert_payload_has_feed_fallback_marker(payload):
        return False
    if _github_dependabot_single_alert_payload_has_hostile_marker(payload):
        return False
    _repo, number = info
    if not _github_dependabot_alert_number_is_safe(payload.get("number")):
        return False
    if payload.get("number") != number:
        return False
    if not _github_dependabot_single_alert_payload_url_matches(origin_uri, payload.get("url")):
        return False
    if not _github_dependabot_single_alert_payload_url_matches(origin_uri, payload.get("html_url"), html=True):
        return False
    if not _github_dependabot_alert_state(payload.get("state")):
        return False
    if _github_dependabot_alert_dependency_info(payload) is None:
        return False
    for container_name in ("security_advisory", "security_vulnerability"):
        if container_name in payload and not _github_dependabot_single_alert_severity_container_is_safe(
            payload.get(container_name)
        ):
            return False
    if not _github_dependabot_alert_severity(payload):
        return False
    return True


def _github_dependabot_single_alert_refresh_summary(origin_uri: str, payload: dict[str, Any]) -> str:
    info = _github_dependabot_single_alert_path_info(origin_uri)
    repo, number = info if info is not None else ("repository", 0)
    dependency = _github_dependabot_alert_dependency_info(payload)
    parts = [f"GitHub Dependabot alert for {repo} #{number}"]
    if dependency is not None:
        ecosystem, name, manifest = dependency
        severity = _github_dependabot_alert_severity(payload)
        parts.append(
            "; ".join([
                f"alert #{int(payload['number'])}: {_safe_public_text(payload.get('state'), limit=40)}",
                f"ecosystem: {ecosystem}",
                f"package: {name}",
                f"manifest: {manifest}",
                f"severity: {severity}",
            ])
        )
    return _bounded_refresh_summary("; ".join(parts))


def _github_security_advisories_path_matches(origin_uri: str) -> bool:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return False
    if not (parts.hostname or "").strip():
        return False

    def _matches_security_advisories_shape(raw_path: str) -> bool:
        path = raw_path.split("/")
        lowered = [segment.lower() for segment in path]
        return (
            len(path) >= 5
            and path[0] == ""
            and lowered[1] == "repos"
            and lowered[4].startswith("security-advisories")
        )

    return _matches_security_advisories_shape(parts.path) or _matches_security_advisories_shape(unquote(parts.path))


def _github_security_advisories_path_repo(origin_uri: str) -> str:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return ""
    if parts.scheme != "https" or parts.netloc != "api.github.com":
        return ""
    path = parts.path.split("/")
    if (
        len(path) != 5
        or path[0] != ""
        or path[1] != "repos"
        or not _github_repo_path_segment_is_safe(path[2])
        or not _github_repo_path_segment_is_safe(path[3])
        or path[4] != "security-advisories"
    ):
        return ""
    return f"{path[2]}/{path[3]}"


def _github_security_advisories_safe_origin(origin_uri: str) -> str:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return ""
    if parts.scheme != "https" or parts.netloc != "api.github.com":
        return ""
    path = parts.path.split("/")
    if (
        len(path) == 5
        and path[0] == ""
        and path[1] == "repos"
        and _github_repo_path_segment_is_safe(path[2])
        and _github_repo_path_segment_is_safe(path[3])
        and path[4] == "security-advisories"
    ):
        return f"https://api.github.com/repos/{path[2]}/{path[3]}/security-advisories"
    return ""


def _github_security_advisories_public_origin(origin_uri: str) -> str:
    repo = _github_security_advisories_path_repo(origin_uri) or _github_security_advisories_path_repo(
        _github_security_advisories_safe_origin(origin_uri)
    )
    if not repo:
        return ""
    return f"github security advisories {repo}"


def _github_security_advisories_origin_is_exact_fetch_origin(origin_uri: str) -> bool:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return False
    return (
        parts.scheme == "https"
        and parts.netloc == "api.github.com"
        and not parts.query
        and not parts.fragment
        and bool(_github_security_advisories_path_repo(origin_uri))
    )


def _github_security_advisories_final_url_matches_origin(origin_uri: str, final_url: Any) -> bool:
    expected = _github_security_advisories_safe_origin(origin_uri)
    if not expected or not isinstance(final_url, str):
        return False
    return final_url == expected and _github_security_advisories_origin_is_exact_fetch_origin(final_url)


def _safe_github_security_advisories_origin_text(value: Any) -> str:
    if not isinstance(value, str):
        return ""
    text = value.strip()
    match = re.fullmatch(r"github security advisories ([A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+)", text)
    if not match:
        return ""
    owner, repo = match.group(1).split("/", 1)
    if not _github_repo_path_segment_is_safe(owner) or not _github_repo_path_segment_is_safe(repo):
        return ""
    return text


_GITHUB_SECURITY_ADVISORIES_DISPLAY_ROUTE_SUBSTRING_RE = re.compile(
    r"(?<![A-Za-z0-9_.-])"
    r"(?:https?://(?:[^\s/@?#]+(?::[^\s/@?#]*)?@)?)?"
    r"api\.github\.com"
    r"(?::\d{1,5})?"
    r"/repos/"
    r"(?P<route_tail>[^\s?#'\"<>)\],;!]+)",
    re.IGNORECASE,
)


def _github_security_advisories_display_route_tail_is_unsafe(route_tail: str) -> bool:
    candidates = {route_tail.lower(), route_tail.lower().replace("%2d", "-")}
    decoded = route_tail
    for _ in range(2):
        next_decoded = unquote(decoded)
        candidates.add(next_decoded.lower())
        candidates.add(next_decoded.lower().replace("%2d", "-"))
        if next_decoded == decoded:
            break
        decoded = next_decoded
    return any("security-advisories" in candidate for candidate in candidates)


def _github_security_advisories_display_name_has_raw_route_substring(value: str) -> bool:
    for match in _GITHUB_SECURITY_ADVISORIES_DISPLAY_ROUTE_SUBSTRING_RE.finditer(value):
        if _github_security_advisories_display_route_tail_is_unsafe(match.group("route_tail")):
            return True
    return False


def _github_security_advisories_display_name_is_unsafe(value: Any) -> bool:
    if not isinstance(value, str):
        return False
    text = value.strip()
    if not text or _safe_github_security_advisories_origin_text(text):
        return False
    return _github_security_advisories_display_name_has_raw_route_substring(text)


def _github_security_advisories_public_display_name(
    display_name: Any,
    *,
    public_origin_uri: Any,
    public_source_id: Any,
    fallback: str = "metadata-only",
) -> str:
    origin_text = _safe_github_security_advisories_origin_text(public_origin_uri)
    if origin_text:
        return origin_text
    public_origin_text = str(public_origin_uri or "").strip()
    if public_origin_text.startswith("capy-memory://") and _github_security_advisories_display_name_is_unsafe(display_name):
        return _safe_public_id(public_source_id, fallback=fallback) or fallback
    return ""


def _github_security_advisories_fetch_origin_from_origin_text(value: Any) -> str:
    text = _safe_github_security_advisories_origin_text(value)
    if not text:
        return ""
    repo = text.removeprefix("github security advisories ")
    owner, name = repo.split("/", 1)
    return f"https://api.github.com/repos/{owner}/{name}/security-advisories"


