def _github_code_scanning_default_setup_language_is_safe(value: Any) -> str:
    return _github_code_scanning_default_setup_token_is_safe(value, limit=40)


def _github_code_scanning_default_setup_languages(value: Any) -> list[str]:
    if value is None:
        return []
    if not isinstance(value, list) or len(value) > 20:
        return []
    languages: list[str] = []
    for item in value:
        language = _github_code_scanning_default_setup_language_is_safe(item)
        if not language:
            return []
        if language not in languages:
            languages.append(language)
    return languages[:10]


def _github_code_scanning_default_setup_languages_are_safe(value: Any) -> bool:
    if not isinstance(value, list) or len(value) > 20:
        return False
    return all(_github_code_scanning_default_setup_language_is_safe(item) for item in value)


def _github_code_scanning_default_setup_payload_is_safe(payload: Any) -> bool:
    if not isinstance(payload, dict) or _json_payload_is_feed(payload) or "items" in payload or "version" in payload:
        return False
    if any(key not in _GITHUB_CODE_SCANNING_DEFAULT_SETUP_ALLOWED_KEYS for key in payload):
        return False
    if not all(
        isinstance(key, str)
        and _github_code_scanning_alert_ignored_key_is_safe(key)
        and _github_code_scanning_alert_ignored_value_is_safe(value)
        for key, value in payload.items()
    ):
        return False
    for field in ("state", "status", "query_suite", "schedule", "runner_type", "runner_label", "threat_model"):
        if field in payload and payload.get(field) is not None:
            if not _github_code_scanning_default_setup_token_is_safe(payload.get(field), limit=80):
                return False
    if "languages" in payload and payload.get("languages") is not None and not _github_code_scanning_default_setup_languages_are_safe(payload.get("languages")):
        return False
    if "updated_at" in payload and payload.get("updated_at") is not None and not _safe_iso_timestamp(payload.get("updated_at")):
        return False
    return any(field in payload for field in _GITHUB_CODE_SCANNING_DEFAULT_SETUP_ALLOWED_KEYS)


def _json_payload_is_github_code_scanning_default_setup_metadata(origin_uri: str, payload: Any) -> bool:
    if not _github_code_scanning_default_setup_path_repo(origin_uri):
        return False
    return _github_code_scanning_default_setup_payload_is_safe(payload)


def _github_code_scanning_default_setup_refresh_summary(origin_uri: str, payload: dict[str, Any]) -> str:
    repo = _github_code_scanning_default_setup_path_repo(origin_uri) or "repository"
    parts = [f"GitHub code scanning default setup for {repo}", f"repository: {repo}"]
    state = _github_code_scanning_default_setup_token_is_safe(payload.get("state"), limit=80)
    if state:
        parts.append(f"state: {state}")
    status = _github_code_scanning_default_setup_token_is_safe(payload.get("status"), limit=80)
    if status:
        parts.append(f"status: {status}")
    languages = _github_code_scanning_default_setup_languages(payload.get("languages"))
    if languages:
        parts.append("languages: " + ", ".join(languages))
    query_suite = _github_code_scanning_default_setup_token_is_safe(payload.get("query_suite"), limit=80)
    if query_suite:
        parts.append(f"query suite: {query_suite}")
    schedule = _github_code_scanning_default_setup_token_is_safe(payload.get("schedule"), limit=80)
    if schedule:
        parts.append(f"schedule: {schedule}")
    runner_type = _github_code_scanning_default_setup_token_is_safe(payload.get("runner_type"), limit=80)
    runner_label = _github_code_scanning_default_setup_token_is_safe(payload.get("runner_label"), limit=80)
    if runner_type and runner_label:
        parts.append(f"runner: {runner_type} {runner_label}")
    elif runner_type:
        parts.append(f"runner: {runner_type}")
    elif runner_label:
        parts.append(f"runner: {runner_label}")
    threat_model = _github_code_scanning_default_setup_token_is_safe(payload.get("threat_model"), limit=80)
    if threat_model:
        parts.append(f"threat model: {threat_model}")
    updated_at = _safe_iso_timestamp(payload.get("updated_at"))
    if updated_at:
        parts.append(f"updated_at: {updated_at}")
    return _bounded_refresh_summary("; ".join(parts))


_GITHUB_CODE_SCANNING_ALERT_STATES = {"dismissed", "fixed", "open"}
_GITHUB_CODE_SCANNING_ALERT_SEVERITIES = {"none", "note", "warning", "error"}
_GITHUB_CODE_SCANNING_ALERT_SECURITY_SEVERITIES = {"low", "medium", "high", "critical", "unknown"}
_GITHUB_CODE_SCANNING_ALERTS_MAX_ROWS = 100


def _github_code_scanning_alert_number_is_safe(value: Any) -> bool:
    return not isinstance(value, bool) and isinstance(value, int) and 0 < value <= 10_000_000_000


def _github_code_scanning_alert_text_is_safe(value: Any, *, limit: int = 200) -> str:
    if not isinstance(value, str):
        return ""
    text = value.strip()
    if not text or text != value:
        return ""
    if _safe_public_text(text, limit=limit) != text or _refresh_value_is_blocked(text):
        return ""
    return text


def _github_code_scanning_alert_rule_id_is_safe(value: Any) -> str:
    text = _github_code_scanning_alert_text_is_safe(value, limit=200)
    if not text:
        return ""
    if _REFRESH_TITLE_BLOCKED_VALUE_RE.search(text):
        return ""
    if not re.fullmatch(r"[A-Za-z0-9][A-Za-z0-9._:/@+-]{0,199}", text):
        return ""
    return text


def _github_code_scanning_alert_rule_name_is_safe(value: Any) -> str:
    text = _github_code_scanning_alert_text_is_safe(value, limit=160)
    if not text:
        return ""
    if _REFRESH_TITLE_BLOCKED_VALUE_RE.search(text):
        return ""
    return text


def _github_code_scanning_alert_rule_info(row: dict[str, Any]) -> tuple[str, str, str, str] | None:
    rule = row.get("rule")
    if not isinstance(rule, dict):
        return None
    rule_id = _github_code_scanning_alert_rule_id_is_safe(rule.get("id"))
    rule_name = _github_code_scanning_alert_rule_name_is_safe(rule.get("name") or rule.get("id"))
    severity = str(rule.get("severity") or "").lower()
    security_severity = str(rule.get("security_severity_level") or "unknown").lower()
    if not rule_id or not rule_name:
        return None
    if severity not in _GITHUB_CODE_SCANNING_ALERT_SEVERITIES:
        return None
    if security_severity not in _GITHUB_CODE_SCANNING_ALERT_SECURITY_SEVERITIES:
        return None
    return rule_id, rule_name, severity, security_severity


_GITHUB_CODE_SCANNING_UNSAFE_IGNORED_KEY_TOKENS = {
    "api",
    "apiauth",
    "auth",
    "authorization",
    "bearer",
    "body",
    "code",
    "credential",
    "data",
    "generatedbody",
    "generatedcode",
    "html",
    "password",
    "rawcontent",
    "renderer",
    "rendercode",
    "sarif",
    "sarifid",
    "script",
    "secret",
    "source",
    "token",
    "widgetbody",
}


def _github_code_scanning_alert_ignored_key_is_safe(key: str) -> bool:
    if _refresh_value_is_blocked(key):
        return False
    collapsed = re.sub(r"[^a-z0-9]+", "", key.lower())
    if collapsed in _GITHUB_CODE_SCANNING_UNSAFE_IGNORED_KEY_TOKENS:
        return False
    camel_spaced = re.sub(r"([a-z0-9])([A-Z])", r"\1 \2", key)
    camel_spaced = re.sub(r"([A-Z]+)([A-Z][a-z])", r"\1 \2", camel_spaced)
    tokens = [token for token in re.split(r"[^a-z0-9]+", camel_spaced.lower()) if token]
    return not any(token in _GITHUB_CODE_SCANNING_UNSAFE_IGNORED_KEY_TOKENS for token in tokens)


def _github_code_scanning_alert_ignored_value_is_safe(value: Any) -> bool:
    if isinstance(value, dict):
        return all(
            isinstance(key, str)
            and _github_code_scanning_alert_ignored_key_is_safe(key)
            and _github_code_scanning_alert_ignored_value_is_safe(item)
            for key, item in value.items()
        )
    if isinstance(value, list):
        return all(_github_code_scanning_alert_ignored_value_is_safe(item) for item in value)
    if isinstance(value, _PUBLIC_SCALAR_TYPES):
        text = str(value)
        return not (
            _refresh_value_is_blocked(value)
            or _UNSAFE_VALUE_RE.search(text)
            or _UNSAFE_PUBLIC_VALUE_RE.search(text)
        )
    return not _refresh_value_is_blocked(value)


def _github_code_scanning_alert_row_is_safe(row: Any) -> bool:
    if not isinstance(row, dict):
        return False
    allowed_keys = {
        "created_at",
        "dismissed_at",
        "dismissed_by",
        "dismissed_comment",
        "dismissed_reason",
        "fixed_at",
        "html_url",
        "instances_url",
        "most_recent_instance",
        "number",
        "rule",
        "state",
        "tool",
        "url",
        "updated_at",
    }
    if any(key not in allowed_keys for key in row):
        return False
    if not all(_github_code_scanning_alert_ignored_value_is_safe(value) for value in row.values()):
        return False
    if not _github_code_scanning_alert_number_is_safe(row.get("number")):
        return False
    if row.get("state") not in _GITHUB_CODE_SCANNING_ALERT_STATES:
        return False
    if _github_code_scanning_alert_rule_info(row) is None:
        return False
    for field in ("created_at", "updated_at", "dismissed_at", "fixed_at"):
        if field in row and row.get(field) is not None and not _safe_iso_timestamp(row.get(field)):
            return False
    return True


def _json_payload_is_github_code_scanning_alerts_metadata(origin_uri: str, payload: Any) -> bool:
    if not _github_code_scanning_alerts_path_repo(origin_uri):
        return False
    if not isinstance(payload, list):
        return False
    if len(payload) > _GITHUB_CODE_SCANNING_ALERTS_MAX_ROWS:
        return False
    return all(_github_code_scanning_alert_row_is_safe(row) for row in payload)


def _github_code_scanning_single_alert_payload_is_safe(payload: Any) -> bool:
    if not isinstance(payload, dict) or _json_payload_is_feed(payload) or "items" in payload or "version" in payload:
        return False
    return _github_code_scanning_alert_row_is_safe(payload)


def _json_payload_is_github_code_scanning_single_alert_metadata(origin_uri: str, payload: Any) -> bool:
    path_info = _github_code_scanning_single_alert_path_info(origin_uri)
    if path_info is None or not isinstance(payload, dict):
        return False
    repo, alert_number = path_info
    owner, name = repo.split("/", 1)
    canonical_origin = _github_code_scanning_single_alert_safe_origin(origin_uri)
    expected_route_fields = {
        "url": canonical_origin,
        "html_url": f"https://github.com/{owner}/{name}/security/code-scanning/{alert_number}",
        "instances_url": f"{canonical_origin}/instances",
    }
    if any(payload.get(field) != expected for field, expected in expected_route_fields.items()):
        return False
    return payload.get("number") == alert_number and _github_code_scanning_single_alert_payload_is_safe(payload)


