def _github_code_scanning_alert_instance_commit_prefix(value: Any) -> str:
    if not isinstance(value, str):
        return ""
    text = value.strip()
    if text != value or not re.fullmatch(r"[0-9a-fA-F]{12,64}", text):
        return ""
    return text[:12].lower()


def _github_code_scanning_alert_instance_line(value: Any) -> int | None:
    if isinstance(value, bool) or not isinstance(value, int):
        return None
    if value <= 0 or value > 10_000_000:
        return None
    return value


def _github_code_scanning_alert_instance_path_is_safe(value: Any) -> bool:
    if value is None:
        return True
    if not isinstance(value, str):
        return False
    text = value.strip()
    if text != value or not text or len(text) > 500:
        return False
    if _safe_public_text(text, limit=500) != text or _refresh_value_is_blocked(text):
        return False
    if re.search(r"(^|/|\\)\.\.($|/|\\)|\\|\x00|https?://|www\.|@", text, flags=re.IGNORECASE):
        return False
    return bool(re.fullmatch(r"[A-Za-z0-9 ._/:+@-]+", text))


def _github_code_scanning_alert_instance_location_is_safe(value: Any) -> bool:
    if value is None:
        return True
    if not isinstance(value, dict):
        return False
    if any(key not in _GITHUB_CODE_SCANNING_ALERT_INSTANCE_LOCATION_ALLOWED_KEYS for key in value):
        return False
    if not all(
        isinstance(key, str)
        and _github_code_scanning_alert_ignored_key_is_safe(key)
        and _github_code_scanning_alert_ignored_value_is_safe(item)
        for key, item in value.items()
    ):
        return False
    if not _github_code_scanning_alert_instance_path_is_safe(value.get("path")):
        return False
    start_line = _github_code_scanning_alert_instance_line(value.get("start_line")) if "start_line" in value else None
    end_line = _github_code_scanning_alert_instance_line(value.get("end_line")) if "end_line" in value else None
    if "start_line" in value and start_line is None:
        return False
    if "end_line" in value and end_line is None:
        return False
    if start_line is not None and end_line is not None and end_line < start_line:
        return False
    for column_field in ("start_column", "end_column"):
        if column_field in value and _github_code_scanning_alert_instance_line(value.get(column_field)) is None:
            return False
    return True


def _github_code_scanning_alert_instance_row_is_safe(row: Any) -> bool:
    if not isinstance(row, dict):
        return False
    if any(key not in _GITHUB_CODE_SCANNING_ALERT_INSTANCE_ALLOWED_KEYS for key in row):
        return False
    if not all(_github_code_scanning_alert_ignored_value_is_safe(value) for value in row.values()):
        return False
    if "ref" in row and not _github_code_scanning_alert_instance_ref_is_safe(row.get("ref")):
        return False
    if "state" in row and row.get("state") not in _GITHUB_CODE_SCANNING_ALERT_STATES:
        return False
    if "category" in row and not _github_code_scanning_alert_instance_category_is_safe(row.get("category")):
        return False
    if "analysis_key" in row and not _github_code_scanning_alert_instance_analysis_key_is_safe(row.get("analysis_key")):
        return False
    if "commit_sha" in row and not _github_code_scanning_alert_instance_commit_prefix(row.get("commit_sha")):
        return False
    if not _github_code_scanning_alert_instance_location_is_safe(row.get("location")):
        return False
    return any(
        (
            _github_code_scanning_alert_instance_ref_is_safe(row.get("ref")),
            row.get("state") in _GITHUB_CODE_SCANNING_ALERT_STATES,
            _github_code_scanning_alert_instance_category_is_safe(row.get("category")),
            _github_code_scanning_alert_instance_analysis_key_is_safe(row.get("analysis_key")),
            _github_code_scanning_alert_instance_commit_prefix(row.get("commit_sha")),
            isinstance(row.get("location"), dict) and "start_line" in row["location"],
        )
    )


