    if not isinstance(location, dict):
        return ""
    start_line = _github_code_scanning_alert_instance_line(location.get("start_line")) if "start_line" in location else None
    end_line = _github_code_scanning_alert_instance_line(location.get("end_line")) if "end_line" in location else None
    if start_line is None:
        return ""
    if end_line is not None and end_line != start_line:
        return f"{start_line}-{end_line}"
    return str(start_line)


