def _github_pages_latest_build_error_message_is_safe(value: Any) -> bool:
    if value is None:
        return True
    if not isinstance(value, str):
        return False
    text = _safe_public_text(value, limit=160)
    if not text or text != value:
        return False
    if _refresh_value_is_blocked(text) or _REFRESH_TITLE_BLOCKED_VALUE_RE.search(text):
        return False
    normalized = re.sub(r"[^a-z0-9]+", "", unquote(text).lower())
    if any(marker in normalized for marker in _GITHUB_PAGES_LATEST_BUILD_ERROR_MESSAGE_BLOCKED_MARKERS):
        return False
    if not re.fullmatch(r"[A-Za-z0-9][A-Za-z0-9.,:;!?()'\" _/-]{0,159}", text):
        return False
    return True


def _github_pages_latest_build_error_is_safe(value: Any) -> bool:
    if value is None:
        return True
    if not isinstance(value, dict):
        return False
    if not set(value).issubset(_GITHUB_PAGES_LATEST_BUILD_ERROR_ALLOWED_KEYS):
        return False
    if not _github_pages_latest_build_error_message_is_safe(value.get("message")):
        return False
    for error_key, error_value in value.items():
        if error_key == "message" or error_value is None:
            continue
        text = _safe_public_text(error_value, limit=80)
        if not text or _refresh_value_is_blocked(text) or _REFRESH_TITLE_BLOCKED_VALUE_RE.search(text):
            return False
        if not re.fullmatch(r"[A-Za-z0-9][A-Za-z0-9._ -]{0,79}", text):
            return False
    return True


def _github_pages_latest_build_payload_is_metadata(row: Any) -> bool:
    if not isinstance(row, dict):
        return False
    if not set(row).issubset(_GITHUB_PAGES_LATEST_BUILD_ALLOWED_KEYS):
        return False
    if _json_payload_is_feed(row) or "items" in row or "version" in row:
        return False
    if "id" in row and row.get("id") is not None and not _github_pages_build_id_is_safe(row.get("id")):
        return False
    if row.get("status") not in _GITHUB_PAGES_STATUSES:
        return False
    if "commit" in row and row.get("commit") is not None and not _github_pages_build_sha_prefix(row.get("commit")):
        return False
    for field in ("created_at", "updated_at"):
        if field in row and row.get(field) is not None and not _github_pages_build_timestamp(row.get(field)):
            return False
    if "duration" in row and row.get("duration") is not None and _github_pages_build_duration(row.get("duration")) is None:
        return False
    if "url" in row and row.get("url") is not None and not _github_pages_ignored_latest_build_url_value_is_safe(row.get("url")):
        return False
    if not _github_pages_latest_build_pusher_is_safe(row.get("pusher")):
        return False
    return _github_pages_latest_build_error_is_safe(row.get("error"))


def _json_payload_is_github_pages_builds_metadata(origin_uri: str, payload: Any) -> bool:
    if not _github_pages_builds_path_repo(origin_uri):
        return False
    if isinstance(payload, dict) and _json_payload_is_feed(payload):
        return False
    if not isinstance(payload, list):
        return False
    if len(payload) > _GITHUB_PAGES_BUILDS_MAX_ROWS:
        return False
    return all(_github_pages_build_row_is_metadata(row) for row in payload)


def _json_payload_is_github_pages_latest_build_metadata(origin_uri: str, payload: Any) -> bool:
    if not _github_pages_latest_build_path_repo(origin_uri):
        return False
    if not isinstance(payload, dict):
        return False
    if _json_payload_is_feed(payload) or "items" in payload or "version" in payload:
        return False
    return _github_pages_latest_build_payload_is_metadata(payload)


def _github_pages_build_row_refresh_summary(row: dict[str, Any]) -> str:
    build_id = row.get("id")
    if _github_pages_build_id_is_safe(build_id):
        row_parts = [f"build #{build_id}: {row.get('status')}"]
    else:
        row_parts = [f"status: {row.get('status')}"]
    sha_prefix = _github_pages_build_sha_prefix(row.get("commit"))
    if sha_prefix:
        row_parts.append(f"sha: {sha_prefix}")
    pusher_login = _github_pages_build_pusher_login(row.get("pusher"))
    if pusher_login:
        row_parts.append(f"pusher: {pusher_login}")
    for field, label in (("created_at", "created at"), ("updated_at", "updated at")):
        timestamp = _github_pages_build_timestamp(row.get(field))
        if timestamp:
            row_parts.append(f"{label}: {timestamp}")
    duration = _github_pages_build_duration(row.get("duration"))
    if duration is not None:
        row_parts.append(f"duration: {duration}")
    row_parts.append(f"error present: {str(row.get('error') is not None).lower()}")
    return "; ".join(row_parts)


def _github_pages_builds_refresh_summary(origin_uri: str, payload: list[Any]) -> str:
    repo = _github_pages_builds_path_repo(origin_uri) or "repository"
    parts = [f"GitHub Pages builds for {repo}", f"build count: {len(payload)}"]
    for row in payload[:5]:
        if not isinstance(row, dict):
            continue
        row_summary = _github_pages_build_row_refresh_summary(row)
        if row_summary:
            parts.append(row_summary)
    return _bounded_refresh_summary("; ".join(parts))


def _github_pages_latest_build_refresh_summary(origin_uri: str, payload: dict[str, Any]) -> str:
    repo = _github_pages_latest_build_path_repo(origin_uri) or "repository"
    row_summary = _github_pages_build_row_refresh_summary(payload)
    return _bounded_refresh_summary("; ".join(part for part in (f"GitHub Pages latest build for {repo}", row_summary) if part))


def _github_teams_path_matches(origin_uri: str) -> bool:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return False
    if not (parts.hostname or "").strip():
        return False

    def _segment_looks_like_teams(raw_segment: str) -> bool:
        segment = raw_segment.lower()
        return segment == "teams" or segment.startswith("teams")

    def _matches_teams_shape(raw_path: str) -> bool:
        path = raw_path.split("/")
        lowered = [segment.lower() for segment in path]
        return len(path) >= 5 and path[0] == "" and lowered[1] == "repos" and any(
            _segment_looks_like_teams(segment) for segment in path[4:]
        )

    return _matches_teams_shape(parts.path) or _matches_teams_shape(unquote(parts.path))


def _github_teams_path_repo(origin_uri: str) -> str:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return ""
    if (parts.hostname or "").strip().lower() != "api.github.com" or parts.scheme != "https" or parts.netloc != "api.github.com":
        return ""
    path = parts.path.split("/")
    if (
        len(path) != 5
        or path[0] != ""
        or path[1] != "repos"
        or not _github_repo_path_segment_is_safe(path[2])
        or not _github_repo_path_segment_is_safe(path[3])
        or path[4] != "teams"
    ):
        return ""
    return f"{path[2]}/{path[3]}"


def _github_team_name_is_safe(value: Any) -> bool:
    if not isinstance(value, str):
        return False
    text = value.strip()
    if not text or text != value:
        return False
    if _safe_public_text(text, limit=120) != text or _refresh_value_is_blocked(text):
        return False
    return bool(re.fullmatch(r"[A-Za-z0-9][A-Za-z0-9 ._()+,@/-]{0,119}", text))


def _github_team_slug_is_safe(value: Any) -> bool:
    if not isinstance(value, str):
        return False
    slug = value.strip()
    if not slug or slug != value:
        return False
    if _refresh_value_is_blocked(slug):
        return False
    return bool(re.fullmatch(r"[a-z0-9](?:[a-z0-9-]{0,98}[a-z0-9])?", slug))


def _github_team_id_is_safe(value: Any) -> bool:
    return not isinstance(value, bool) and isinstance(value, int) and 0 < value <= 10_000_000_000


def _github_team_privacy_is_safe(value: Any) -> bool:
    return value in {"closed", "secret"}


def _github_team_permission_is_safe(value: Any) -> bool:
    return value in {"pull", "triage", "push", "maintain", "admin", "read", "write"}


def _github_team_ignored_value_is_safe(value: Any) -> bool:
    if isinstance(value, dict):
        return all(
            isinstance(key, str)
            and not _refresh_value_is_blocked(key)
            and _github_team_ignored_value_is_safe(item)
            for key, item in value.items()
        )
    if isinstance(value, list):
        return all(_github_team_ignored_value_is_safe(item) for item in value)
    return not _refresh_value_is_blocked(value)


def _github_team_row_is_safe(row: Any) -> bool:
    if not isinstance(row, dict):
        return False
    allowed_summary_keys = {"id", "name", "slug", "privacy", "permission"}
    allowed_ignored_keys = {
        "description",
        "html_url",
        "members_url",
        "notification_setting",
        "node_id",
        "parent",
        "permission",
        "privacy",
        "repositories_url",
        "slug",
        "url",
    }
    for key, value in row.items():
        if key in allowed_summary_keys:
            continue
        if key not in allowed_ignored_keys or not _github_team_ignored_value_is_safe(value):
            return False
    if not _github_team_id_is_safe(row.get("id")):
        return False
    if not _github_team_name_is_safe(row.get("name")):
        return False
    if not _github_team_slug_is_safe(row.get("slug")):
        return False
    if not _github_team_privacy_is_safe(row.get("privacy")):
        return False
    if "permission" in row and not _github_team_permission_is_safe(row.get("permission")):
        return False
    return True


def _json_payload_is_github_teams_metadata(origin_uri: str, payload: Any) -> bool:
    if not _github_teams_path_repo(origin_uri):
        return False
    if not isinstance(payload, list):
        return False
    if len(payload) > 100:
        return False
    return all(_github_team_row_is_safe(row) for row in payload)


def _github_teams_refresh_summary(origin_uri: str, payload: list[Any]) -> str:
    repo = _github_teams_path_repo(origin_uri) or "repository"
    safe_rows = [row for row in payload if _github_team_row_is_safe(row)]
    parts = [f"GitHub teams for {repo}", f"team count: {len(payload)}"]
    for row in safe_rows[:5]:
        privacy = _safe_public_text(row.get("privacy"), limit=20)
        if row.get("privacy") == "secret":
            privacy = "private"
        row_parts = [
            f"team: {_safe_public_text(row.get('name'), limit=120).lower()}",
            f"slug: {_safe_public_text(row.get('slug'), limit=100)}",
            f"id: {int(row.get('id'))}",
            f"privacy: {privacy}",
        ]
        if "permission" in row:
            row_parts.append(f"permission: {_safe_public_text(row.get('permission'), limit=20)}")
        parts.append("; ".join(row_parts))
    return _bounded_refresh_summary("; ".join(parts))


def _github_repository_invitations_route_path_matches(origin_uri: str) -> bool:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return False

    def _segment_looks_like_invitations_route_marker(raw_segment: str) -> bool:
        return raw_segment.lower().startswith("invitations")

    def _has_no_repo_subroute(path: list[str]) -> bool:
        return len(path) == 4 or (len(path) == 5 and path[4] == "")

    def _matches_invitations_shape(raw_path: str) -> bool:
        path = raw_path.split("/")
        lowered = [segment.lower() for segment in path]
        if len(path) < 4 or path[0] != "" or len(lowered) <= 1 or lowered[1] != "repos":
            return False
        if _has_no_repo_subroute(path) and _segment_looks_like_invitations_route_marker(path[3]):
            return True
        return len(path) >= 5 and _segment_looks_like_invitations_route_marker(path[4])

    return _matches_invitations_shape(parts.path) or _matches_invitations_shape(unquote(parts.path))


def _github_repository_invitations_safe_origin(origin_uri: str) -> str:
    try:
        parts = urlsplit(origin_uri)
        explicit_port = parts.port is not None
    except ValueError:
        return ""
    if parts.scheme != "https" or explicit_port or not _github_raw_authority_is_exact(origin_uri, "api.github.com"):
        return ""
    path = parts.path.split("/")
    if (
        len(path) != 5
        or path[0] != ""
        or path[1] != "repos"
        or not _github_repo_path_segment_is_safe(path[2])
        or not _github_repo_path_segment_is_safe(path[3])
        or path[4] != "invitations"
    ):
        return ""
    return urlunsplit(("https", "api.github.com", parts.path, "", ""))


def _github_repository_invitations_path_repo(origin_uri: str) -> str:
    try:
        parts = urlsplit(origin_uri)
    except ValueError:
        return ""
    if parts.scheme != "https" or not _github_raw_authority_is_exact(origin_uri, "api.github.com"):
        return ""
    path = parts.path.split("/")
    if (
        len(path) != 5
        or path[0] != ""
        or path[1] != "repos"
        or not _github_repo_path_segment_is_safe(path[2])
        or not _github_repo_path_segment_is_safe(path[3])
        or path[4] != "invitations"
    ):
        return ""
    return f"{path[2]}/{path[3]}"


def _github_repository_invitations_path_matches(origin_uri: str) -> bool:
    return bool(_github_repository_invitations_path_repo(origin_uri))


def _github_repository_invitations_final_url_matches_origin(origin_uri: str, final_url: Any) -> bool:
    if not isinstance(final_url, str):
        return False
    expected_origin = _github_repository_invitations_safe_origin(origin_uri)
    if not expected_origin or expected_origin != origin_uri:
        return False
    if not _github_raw_authority_is_exact(final_url, "api.github.com"):
        return False
    safe_final_url = _github_repository_invitations_safe_origin(final_url)
    if not safe_final_url:
        return False
    if final_url != safe_final_url or final_url != expected_origin or final_url != origin_uri:
        return False
    return _github_repository_invitations_path_repo(final_url) == _github_repository_invitations_path_repo(origin_uri)


def _github_repository_invitations_origin_text(origin_uri: str) -> str:
    repo = _github_repository_invitations_path_repo(origin_uri)
    if not repo:
        return ""
    return f"github repository invitations {repo}"


def _safe_github_repository_invitations_origin_text(value: Any) -> str:
    text = str(value or "").strip()
    match = re.fullmatch(
        r"github repository invitations ([A-Za-z0-9][A-Za-z0-9._-]{0,119})/([A-Za-z0-9][A-Za-z0-9._-]{0,119})",
        text,
        flags=re.IGNORECASE,
    )
    if not match:
        return ""
    owner, repo = match.groups()
    if not _github_repo_path_segment_is_safe(owner) or not _github_repo_path_segment_is_safe(repo):
        return ""
    return f"github repository invitations {owner}/{repo}"


def _github_repository_invitations_fetch_origin_from_origin_text(value: Any) -> str:
    text = _safe_github_repository_invitations_origin_text(value)
    if not text:
        return ""
    match = re.fullmatch(
        r"github repository invitations ([A-Za-z0-9][A-Za-z0-9._-]{0,119})/([A-Za-z0-9][A-Za-z0-9._-]{0,119})",
        text,
        flags=re.IGNORECASE,
    )
    if not match:
        return ""
    owner, repo = match.groups()
    return f"https://api.github.com/repos/{owner}/{repo}/invitations"


def _github_repository_single_invitation_route_path_matches(origin_uri: str) -> bool:
    try:
        parts = urlsplit(str(origin_uri or ""))
    except ValueError:
        return False

    def _matches_single_invitation_shape(raw_path: str) -> bool:
        path = raw_path.split("/")
        lowered = [segment.lower() for segment in path]
        if len(path) < 5 or path[0] != "" or len(lowered) <= 1 or lowered[1] != "repos":
            return False
        if len(path) >= 6 and lowered[4].startswith("invitations"):
            return True
        return (
            len(path) >= 5
            and lowered[3].startswith("invitations")
            and path[4].lstrip("-").isdigit()
        )

    return _matches_single_invitation_shape(parts.path) or _matches_single_invitation_shape(unquote(parts.path))


def _github_repository_single_invitation_path_info(origin_uri: str) -> tuple[str, int] | None:
    try:
        parts = urlsplit(str(origin_uri or ""))
        explicit_port = parts.port is not None
    except ValueError:
        return None
    if parts.scheme != "https" or explicit_port or not _github_raw_authority_is_exact(origin_uri, "api.github.com"):
        return None
    path = parts.path.split("/")
    if (
        len(path) != 6
        or path[0] != ""
        or path[1] != "repos"
        or not _github_repo_path_segment_is_safe(path[2])
        or not _github_repo_path_segment_is_safe(path[3])
        or path[4] != "invitations"
        or not path[5].isdigit()
    ):
        return None
    invitation_id = int(path[5])
    if not _github_repository_invitation_id_is_safe(invitation_id):
        return None
    return f"{path[2]}/{path[3]}", invitation_id


def _github_repository_single_invitation_safe_origin(origin_uri: str) -> str:
    info = _github_repository_single_invitation_path_info(origin_uri)
    if info is None:
        return ""
    try:
        parts = urlsplit(str(origin_uri or ""))
    except ValueError:
        return ""
    return urlunsplit(("https", "api.github.com", parts.path, "", ""))


def _github_repository_single_invitation_path_matches(origin_uri: str) -> bool:
    return _github_repository_single_invitation_path_info(origin_uri) is not None


def _github_repository_single_invitation_path_repo(origin_uri: str) -> str:
    info = _github_repository_single_invitation_path_info(origin_uri)
    return info[0] if info is not None else ""


def _github_repository_single_invitation_path_invitation_id(origin_uri: str) -> int | None:
    info = _github_repository_single_invitation_path_info(origin_uri)
    return info[1] if info is not None else None


def _github_repository_single_invitation_origin_text(origin_uri: str) -> str:
    info = _github_repository_single_invitation_path_info(origin_uri)
    if info is None:
        return ""
    repo, invitation_id = info
    return f"github repository invitation {repo} #{invitation_id}"


def _safe_github_repository_single_invitation_origin_text(value: Any) -> str:
    text = str(value or "").strip()
    match = re.fullmatch(
        r"github repository invitation ([A-Za-z0-9][A-Za-z0-9._-]{0,119}/[A-Za-z0-9][A-Za-z0-9._-]{0,119}) #([1-9][0-9]{0,17})",
        text,
        flags=re.IGNORECASE,
    )
    if not match:
        return ""
    owner, repo = match.group(1).split("/", 1)
    invitation_id = int(match.group(2))
    if (
        not _github_repo_path_segment_is_safe(owner)
        or not _github_repo_path_segment_is_safe(repo)
        or not _github_repository_invitation_id_is_safe(invitation_id)
    ):
        return ""
    return f"github repository invitation {owner}/{repo} #{invitation_id}"


def _github_repository_single_invitation_fetch_origin_from_origin_text(value: Any) -> str:
    text = _safe_github_repository_single_invitation_origin_text(value)
    if not text:
        return ""
    match = re.fullmatch(
        r"github repository invitation ([A-Za-z0-9][A-Za-z0-9._-]{0,119})/([A-Za-z0-9][A-Za-z0-9._-]{0,119}) #([1-9][0-9]{0,17})",
        text,
        flags=re.IGNORECASE,
    )
    if not match:
        return ""
    owner, repo, invitation_id = match.groups()
    return f"https://api.github.com/repos/{owner}/{repo}/invitations/{int(invitation_id)}"


def _github_repository_invitation_id_is_safe(value: Any) -> bool:
    return not isinstance(value, bool) and isinstance(value, int) and 0 < value <= 99_999_999_999_999_999


def _github_repository_invitation_permission_is_safe(value: Any) -> bool:
    return value in {"pull", "triage", "push", "maintain", "admin", "read", "write"}


def _github_repository_invitation_created_at_is_safe(value: Any) -> bool:
    if not isinstance(value, str):
        return False
    text = value.strip()
    if not text or text != value:
        return False
    if _safe_public_text(text, limit=40) != text or _refresh_value_is_blocked(text):
        return False
    return bool(_safe_iso_timestamp(text))


