def _refresh_record_from_text(source_id: str, origin_uri: str, text: str, *, content_type: str) -> dict[str, Any]:
    source_text = text
    title = ""
    summary = ""
    if content_type == "text/html":
        parser = _RefreshMetadataParser()
        parser.feed(source_text)
        parser.close()
        title = _safe_public_text(" ".join(parser.title_parts), limit=200)
        summary = _bounded_refresh_summary(" ".join(parser.description_parts))
    else:
        lines = []
        for line in source_text.splitlines():
            if re.match(r"^\s*(summary|description)\s*:", line, flags=re.IGNORECASE):
                lines.append(re.sub(r"^\s*(summary|description)\s*:\s*", "", line, flags=re.IGNORECASE))
        summary = _bounded_refresh_summary(" ".join(lines))
    if not summary:
        raise ValueError("refresh failed")
    return {
        "metadata_only": True,
        "title": title or source_id,
        "summary": summary,
        "origin_uri": _safe_origin_uri(origin_uri, source_id=source_id),
    }


def _xml_local_name(tag: Any) -> str:
    text = str(tag or "")
    if "}" in text:
        text = text.rsplit("}", 1)[-1]
    if ":" in text:
        text = text.rsplit(":", 1)[-1]
    return text.strip().lower()


def _refresh_xml_child_text(parent: ElementTree.Element, names: set[str]) -> str:
    for child in list(parent):
        if _xml_local_name(child.tag) in names and not _refresh_xml_has_unsafe_descendant(child):
            return " ".join(part.strip() for part in child.itertext() if part.strip())
    return ""


def _refresh_xml_has_unsafe_descendant(parent: ElementTree.Element) -> bool:
    for descendant in list(parent.iter())[1:]:
        if _UNSAFE_KEY_RE.search(_xml_local_name(descendant.tag)):
            return True
    return False


def _refresh_xml_feed_entries(root: ElementTree.Element) -> list[ElementTree.Element]:
    root_name = _xml_local_name(root.tag)
    if root_name == "feed":
        return [child for child in list(root) if _xml_local_name(child.tag) == "entry"]
    if root_name == "rss":
        entries: list[ElementTree.Element] = []
        for channel in list(root):
            if _xml_local_name(channel.tag) == "channel":
                entries.extend(child for child in list(channel) if _xml_local_name(child.tag) == "item")
        return entries
    if root_name == "rdf":
        return [child for child in list(root) if _xml_local_name(child.tag) == "item"]
    return []


def _refresh_sitemap_lastmod(value: Any) -> str:
    raw = _safe_text(value, limit=80)
    if not raw or _refresh_value_is_blocked(raw):
        return ""
    if re.fullmatch(r"\d{4}-\d{2}-\d{2}", raw):
        return raw
    safe_iso = _safe_iso_timestamp(raw)
    if not safe_iso:
        return ""
    return safe_iso


def _refresh_sitemap_query_has_blocked_param(query: str) -> bool:
    try:
        params = parse_qsl(query, keep_blank_values=True, strict_parsing=False, max_num_fields=100)
    except ValueError:
        return True
    for key, value in params:
        key_text = _safe_text(key, limit=120)
        value_text = _safe_text(value, limit=300)
        normalized_key = re.sub(r"[^a-z0-9]+", "", key_text.lower())
        if normalized_key in _REFRESH_SITEMAP_BLOCKED_QUERY_KEYS:
            return True
        if key_text and _REFRESH_SITEMAP_BLOCKED_QUERY_VALUE_RE.search(key_text):
            return True
        if value_text and (
            _refresh_value_is_blocked(value_text) or _REFRESH_SITEMAP_BLOCKED_QUERY_VALUE_RE.search(value_text)
        ):
            return True
    return False


def _refresh_sitemap_safe_loc(value: Any) -> str:
    raw = _safe_text(value, limit=1_000)
    if not raw or _refresh_value_is_blocked(raw):
        return ""
    try:
        parts = urlsplit(raw)
    except ValueError:
        return ""
    if parts.scheme.lower() != "https" or not parts.netloc:
        return ""
    if parts.username or parts.password or "@" in parts.netloc or parts.fragment:
        return ""
    if parts.query and (
        _refresh_value_is_blocked(parts.query) or _refresh_sitemap_query_has_blocked_param(parts.query)
    ):
        return ""
    try:
        port = parts.port
    except ValueError:
        return ""
    host = _safe_text(parts.hostname or "", limit=200).lower().strip(".")
    if not host or _refresh_value_is_blocked(host) or _UNSAFE_PUBLIC_VALUE_RE.search(host):
        return ""
    path = _safe_text(parts.path or "/", limit=240) or "/"
    if not path.startswith("/"):
        path = f"/{path}"
    decoded_path = unquote(path)
    if _refresh_value_is_blocked(decoded_path):
        return ""
    authority = host
    if port is not None:
        authority = f"{host}:{port}"
    return f"{authority}{path}"


def _refresh_record_from_sitemap_urlset(source_id: str, origin_uri: str, root: ElementTree.Element) -> dict[str, Any]:
    safe_entries: list[dict[str, str]] = []
    for child in list(root):
        if _xml_local_name(child.tag) != "url":
            continue
        loc = _refresh_sitemap_safe_loc(_refresh_xml_child_text(child, {"loc"}))
        if not loc:
            continue
        entry: dict[str, str] = {"loc": loc}
        lastmod = _refresh_sitemap_lastmod(_refresh_xml_child_text(child, {"lastmod"}))
        if lastmod:
            entry["lastmod"] = lastmod
        safe_entries.append(entry)
    if not safe_entries:
        raise ValueError("refresh failed")
    safe_origin = _safe_origin_uri(origin_uri, source_id=source_id)
    try:
        origin_host = (urlsplit(safe_origin).hostname or "").strip().lower()
    except ValueError:
        origin_host = ""
    title_host = _safe_public_text(origin_host or source_id, limit=120) or source_id
    summary_parts = [f"Sitemap for {title_host}", f"url count: {len(safe_entries)}"]
    for entry in safe_entries[:5]:
        item = f"url: {entry['loc']}"
        if entry.get("lastmod"):
            item = f"{item} lastmod: {entry['lastmod']}"
        summary_parts.append(item)
    summary = _bounded_refresh_summary("; ".join(summary_parts))
    if not summary:
        raise ValueError("refresh failed")
    return {
        "metadata_only": True,
        "title": f"Sitemap for {title_host}",
        "summary": summary,
        "origin_uri": safe_origin,
    }


def _refresh_record_from_feed(source_id: str, origin_uri: str, text: str) -> dict[str, Any]:
    if re.search(r"<!\s*(?:doctype|entity)\b", text, flags=re.IGNORECASE):
        raise RuntimeError("refresh fetcher disabled")
    try:
        root = ElementTree.fromstring(text.strip())
    except ElementTree.ParseError as exc:
        raise RuntimeError("refresh fetcher disabled") from exc

    root_name = _xml_local_name(root.tag)
    if root_name == "urlset":
        return _refresh_record_from_sitemap_urlset(source_id, origin_uri, root)
    if root_name not in {"rss", "feed", "rdf"}:
        raise ValueError("refresh failed")
    entries = _refresh_xml_feed_entries(root)
    if not entries:
        raise ValueError("refresh failed")
    containers = entries
    title = ""
    summary = ""
    for container in containers[:5]:
        candidate_summary = _bounded_refresh_summary(
            _refresh_xml_child_text(container, {"description", "summary", "subtitle"})
        )
        if candidate_summary:
            title = _safe_public_text(_refresh_xml_child_text(container, {"title"}), limit=200)
            summary = candidate_summary
            break
